import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/Dialog";
import { Button } from "@/components/ui/Button";
import * as businessApi from "@/apis/businessApi";
import { ADMIN_ROUTES } from "@/constants/routes";
import {
  BUSINESS_STATUS,
  BUSINESS_STATUS_LABELS,
} from "@/constants/businessConstants";
import {
  Loader2,
  MapPin,
  Building2,
  ExternalLink,
  Mail,
} from "lucide-react";
import toast from "react-hot-toast";
import { cn } from "@/lib/utils";

const PLACE_STATUS_LABEL = {
  draft: "Nháp",
  pending: "Chờ duyệt",
  approved: "Đã duyệt",
  rejected: "Từ chối",
  hidden: "Ẩn",
};

/**
 * Chi tiết doanh nghiệp (admin) + danh sách địa điểm trực thuộc.
 */
export default function BusinessDetailModal({
  open,
  onOpenChange,
  businessId,
}) {
  const [detail, setDetail] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!open || !businessId) return;
    let cancelled = false;
    setDetail(null);
    (async () => {
      setLoading(true);
      try {
        const res = await businessApi.getById(businessId);
        if (!cancelled) setDetail(res.data);
      } catch (e) {
        if (!cancelled) {
          toast.error(e.message || "Không tải được doanh nghiệp");
          onOpenChange?.(false);
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [open, businessId, onOpenChange]);

  const statusLabel =
    detail?.status != null
      ? BUSINESS_STATUS_LABELS[detail.status] || detail.status
      : "—";

  const places = Array.isArray(detail?.places) ? detail.places : [];

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-h-[min(90vh,840px)] max-w-3xl overflow-hidden flex flex-col gap-0 rounded-none border-2 border-black p-0 sm:rounded-none">
        <DialogHeader className="shrink-0 border-b-2 border-black bg-[#F4F4F4] px-5 py-4 text-left">
          <DialogTitle className="flex items-center gap-2 font-black uppercase tracking-tight text-base">
            <Building2 className="h-5 w-5 shrink-0" aria-hidden />
            Doanh nghiệp & địa điểm
          </DialogTitle>
          <DialogDescription className="font-mono text-[11px] uppercase text-muted-foreground">
            Phạm vi hoạt động: các địa điểm gắn với doanh nghiệp này
          </DialogDescription>
        </DialogHeader>

        <div className="min-h-0 flex-1 overflow-y-auto px-5 py-4 space-y-4">
          {loading ? (
            <div className="flex justify-center py-16 text-muted-foreground">
              <Loader2 className="h-8 w-8 animate-spin" aria-hidden />
            </div>
          ) : detail ? (
            <>
              <div className="border border-black bg-white p-4 space-y-2">
                <div className="flex flex-wrap items-start justify-between gap-2">
                  <div>
                    <p className="font-mono text-[10px] uppercase text-muted-foreground">
                      Tên doanh nghiệp
                    </p>
                    <p className="font-black text-lg uppercase tracking-tight">
                      {detail.businessName || "—"}
                    </p>
                  </div>
                  <span
                    className={cn(
                      "font-mono text-[10px] uppercase px-2 py-1 border border-black",
                      detail.status === BUSINESS_STATUS.APPROVED &&
                        "bg-[#F3E600] text-black",
                      detail.status === BUSINESS_STATUS.PENDING &&
                        "bg-amber-100 text-amber-900",
                      detail.status === BUSINESS_STATUS.SUSPENDED &&
                        "bg-neutral-200 text-neutral-800",
                      detail.status === BUSINESS_STATUS.REJECTED &&
                        "bg-red-100 text-red-800",
                    )}
                  >
                    {statusLabel}
                  </span>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 text-sm">
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <Mail className="h-4 w-4 shrink-0" />
                    <span className="truncate">{detail.owner?.email || "—"}</span>
                  </div>
                  {detail.commissionRate != null && (
                    <p className="font-mono text-xs">
                      Hoa hồng:{" "}
                      <strong>{Number(detail.commissionRate)}%</strong>
                    </p>
                  )}
                </div>
              </div>

              <div>
                <p className="font-mono text-[10px] font-bold uppercase tracking-wider text-muted-foreground mb-2 flex items-center gap-1.5">
                  <MapPin className="h-3.5 w-3.5" />
                  Địa điểm ({places.length})
                </p>
                {places.length === 0 ? (
                  <p className="text-sm text-muted-foreground border border-dashed border-black/30 p-6 text-center">
                    Chưa có địa điểm nào gắn với doanh nghiệp này.
                  </p>
                ) : (
                  <div className="border border-black divide-y divide-black">
                    {places.map((p) => (
                      <div
                        key={p.id}
                        className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2 p-3 bg-white hover:bg-muted/40 transition-colors"
                      >
                        <div className="min-w-0 space-y-0.5">
                          <p className="font-semibold text-sm truncate">
                            {p.name}
                          </p>
                          <p className="text-[11px] text-muted-foreground truncate">
                            {[p.category?.name, p.district?.name]
                              .filter(Boolean)
                              .join(" · ") || p.address || "—"}
                          </p>
                          <span className="inline-block font-mono text-[10px] uppercase border border-black/20 px-1.5 py-0.5">
                            {PLACE_STATUS_LABEL[p.status] || p.status}
                          </span>
                        </div>
                        <Button
                          variant="outline"
                          size="sm"
                          asChild
                          className="rounded-none border-black shrink-0 font-mono text-[10px] uppercase"
                        >
                          <Link
                            to={ADMIN_ROUTES.PLACES_EDIT(p.id)}
                            onClick={() => onOpenChange?.(false)}
                          >
                            Sửa địa điểm
                            <ExternalLink className="h-3 w-3 ml-1" />
                          </Link>
                        </Button>
                      </div>
                    ))}
                  </div>
                )}
                <p className="mt-2 text-[11px] text-muted-foreground">
                  <Link
                    to={`${ADMIN_ROUTES.PLACES}?businessId=${businessId}`}
                    className="underline font-medium text-foreground hover:text-primary"
                    onClick={() => onOpenChange?.(false)}
                  >
                    Lọc danh sách địa điểm theo doanh nghiệp này
                  </Link>{" "}
                  (nếu trang địa điểm hỗ trợ tham số).
                </p>
              </div>
            </>
          ) : null}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useEffect, useMemo, useState } from "react";
import toast from "react-hot-toast";
import { Link } from "react-router-dom";
import {
  ExternalLink,
  FileText,
  ImageIcon,
  Loader2,
  MapPin,
  User,
} from "lucide-react";
import { ADMIN_ROUTES } from "@/constants/routes";
import * as businessApi from "@/apis/businessApi";
import { BUSINESS_TYPE_LABELS } from "@/constants/businessConstants";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/Dialog";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Label } from "@/components/ui/Label";
import { Checkbox } from "@/components/ui/checkbox";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";
import {
  resolveMediaUrl,
  isPdfSource,
  isImageSource,
} from "@/utils/mediaUrl";

const FieldRow = ({ label, value, mono }) => (
  <div className="flex flex-col sm:flex-row sm:gap-3 sm:justify-between py-2.5 border-b border-border/40 last:border-0 first:pt-0 text-sm">
    <span className="text-muted-foreground shrink-0 w-44">{label}</span>
    <span
      className={cn(
        "font-medium text-foreground text-right sm:text-left flex-1 break-words",
        mono && "font-mono text-xs",
      )}
    >
      {value !== undefined && value !== null && value !== ""
        ? String(value)
        : "—"}
    </span>
  </div>
);

/**
 * Thẻ xem nhanh giấy tờ: hỗ trợ URL https, data URI ảnh/PDF, đường dẫn /... ghép origin API.
 */
function DocumentPreviewCard({ title, raw }) {
  const resolved = useMemo(() => resolveMediaUrl(raw), [raw]);
  const [imgError, setImgError] = useState(false);

  useEffect(() => {
    const id = requestAnimationFrame(() => setImgError(false));
    return () => cancelAnimationFrame(id);
  }, [resolved]);

  const isPdf = resolved && isPdfSource(resolved);
  const isImgHint = resolved && isImageSource(resolved);

  if (!resolved) {
    return (
      <div className="flex min-h-[220px] flex-col items-center justify-center rounded-2xl border border-dashed border-muted-foreground/25 bg-muted/20 p-5 text-center shadow-inner">
        <FileText
          className="mb-2 h-10 w-10 text-muted-foreground/45"
          aria-hidden="true"
        />
        <p className="text-sm font-semibold text-foreground">{title}</p>
        <p className="mt-1 text-xs text-muted-foreground">Chưa có tệp đính kèm</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col overflow-hidden rounded-2xl border border-border/50 bg-card shadow-md ring-1 ring-black/[0.04] dark:ring-white/10">
      <div className="flex items-center justify-between gap-2 rounded-t-2xl border-b border-border/40 bg-gradient-to-r from-muted/60 to-muted/30 px-4 py-3">
        <p className="truncate text-sm font-semibold text-foreground">{title}</p>
        <a
          href={resolved}
          target="_blank"
          rel="noopener noreferrer"
          className="inline-flex shrink-0 items-center gap-1.5 rounded-full bg-background/80 px-3 py-1.5 text-xs font-medium text-primary shadow-sm ring-1 ring-border/60 transition hover:bg-muted"
        >
          Toàn màn hình
          <ExternalLink className="h-3.5 w-3.5" aria-hidden="true" />
        </a>
      </div>

      <div className="flex min-h-[220px] flex-1 items-center justify-center rounded-b-2xl bg-muted/20 p-3">
        {isPdf ? (
          <div className="w-full space-y-2">
            <iframe
              title={title}
              src={resolved}
              className="h-[min(42vh,300px)] w-full rounded-xl border border-border/50 bg-background shadow-inner"
            />
            <p className="text-center text-[11px] leading-snug text-muted-foreground">
              Nếu khung PDF trống hoặc bị chặn, dùng &quot;Toàn màn hình&quot; để
              mở trong tab mới.
            </p>
          </div>
        ) : isImgHint || (!isPdf && !imgError) ? (
          <div className="relative flex w-full justify-center">
            {!imgError ? (
              <img
                src={resolved}
                alt={`${title} — đối chiếu`}
                className="max-h-[min(44vh,380px)] w-full rounded-xl border border-border/30 bg-background object-contain shadow-sm"
                loading="lazy"
                decoding="async"
                referrerPolicy="no-referrer"
                onError={() => setImgError(true)}
              />
            ) : (
              <div className="flex flex-col items-center gap-3 px-4 py-8 text-center">
                <ImageIcon className="h-10 w-10 text-muted-foreground/70" />
                <p className="text-xs text-muted-foreground">
                  Không tải được ảnh (link hết hạn, chặn hotlink, hoặc định dạng
                  không hỗ trợ). Hãy mở &quot;Toàn màn hình&quot; để đối chiếu.
                </p>
                <Button variant="outline" size="sm" asChild>
                  <a href={resolved} target="_blank" rel="noopener noreferrer">
                    Mở tệp gốc
                  </a>
                </Button>
              </div>
            )}
          </div>
        ) : (
          <div className="flex flex-col items-center gap-2 px-4 py-8 text-center">
            <FileText className="h-10 w-10 text-muted-foreground/70" />
            <p className="text-xs text-muted-foreground">
              Xem nhanh không khả dụng. Mở tab mới để đối chiếu.
            </p>
            <Button variant="outline" size="sm" asChild>
              <a href={resolved} target="_blank" rel="noopener noreferrer">
                Mở tệp
              </a>
            </Button>
          </div>
        )}
      </div>
    </div>
  );
}

/**
 * Modal đối chiếu đầy đủ trước khi admin duyệt / từ chối doanh nghiệp (trạng thái pending).
 */
const BusinessReviewApproveModal = ({
  open,
  onOpenChange,
  businessId,
  onApproved,
  onRejected,
}) => {
  const [detail, setDetail] = useState(null);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [rejectMode, setRejectMode] = useState(false);
  const [rejectReason, setRejectReason] = useState("");
  const [acknowledged, setAcknowledged] = useState(false);
  const [commissionRate, setCommissionRate] = useState("10");

  useEffect(() => {
    if (!open || !businessId) return;
    let cancelled = false;
    setRejectMode(false);
    setRejectReason("");
    setAcknowledged(false);
    setDetail(null);
    (async () => {
      setLoading(true);
      try {
        const res = await businessApi.getById(businessId);
        if (cancelled) return;
        const data = res.data;
        setDetail(data);
        if (data?.commissionRate != null && data.commissionRate !== "") {
          setCommissionRate(String(Number(data.commissionRate)));
        } else {
          setCommissionRate("10");
        }
      } catch (e) {
        if (!cancelled) {
          toast.error(e.message || "Không tải được hồ sơ");
          onOpenChange?.(false);
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [open, businessId, onOpenChange]);

  const handleApprove = async () => {
    if (!acknowledged) {
      toast.error("Vui lòng xác nhận đã đối chiếu giấy tờ");
      return;
    }
    const rate = Number(commissionRate);
    if (Number.isNaN(rate) || rate < 0 || rate > 100) {
      toast.error("Tỷ lệ hoa hồng phải từ 0 đến 100");
      return;
    }
    setSubmitting(true);
    try {
      await onApproved?.(businessId, { commissionRate: rate });
      toast.success("Đã duyệt doanh nghiệp");
      onOpenChange?.(false);
    } catch (e) {
      toast.error(e.message || "Không thể duyệt");
    } finally {
      setSubmitting(false);
    }
  };

  const handleReject = async () => {
    if (rejectReason.trim().length < 10) {
      toast.error("Lý do từ chối phải có ít nhất 10 ký tự");
      return;
    }
    setSubmitting(true);
    try {
      await onRejected?.(businessId, rejectReason.trim());
      toast.success("Đã từ chối hồ sơ");
      onOpenChange?.(false);
    } catch (e) {
      toast.error(e.message || "Không thể từ chối");
    } finally {
      setSubmitting(false);
    }
  };

  const typeLabel =
    BUSINESS_TYPE_LABELS[detail?.businessType] || detail?.businessType || "—";

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent
        className={cn(
          "max-h-[min(92vh,920px)] max-w-4xl gap-0 overflow-hidden p-0 flex flex-col",
          "rounded-3xl border-border/50 shadow-2xl ring-1 ring-black/[0.06] dark:ring-white/[0.08]",
          "sm:rounded-3xl",
        )}
      >
        <div className="shrink-0 rounded-t-3xl border-b border-border/40 bg-gradient-to-br from-muted/70 via-muted/40 to-background px-6 pb-4 pt-7">
          <DialogHeader className="space-y-2">
            <DialogTitle className="flex items-center gap-3 pr-10 text-xl font-semibold tracking-tight">
              <span className="flex h-10 w-10 items-center justify-center rounded-2xl bg-primary/10 text-primary">
                <FileText className="h-5 w-5 shrink-0" aria-hidden="true" />
              </span>
              Đối chiếu hồ sơ doanh nghiệp
            </DialogTitle>
            <DialogDescription className="text-[13px] leading-relaxed">
              Xem ảnh/PDF trực tiếp bên dưới; dùng &quot;Toàn màn hình&quot; nếu
              cần phóng to. Chỉ duyệt sau khi đối chiếu thực tế với bản gốc.
            </DialogDescription>
          </DialogHeader>
        </div>

        <div className="min-h-0 flex-1 overflow-y-auto px-6 pb-6 pt-5 space-y-6">
          {loading ? (
            <div className="flex justify-center py-20 text-muted-foreground">
              <Loader2 className="h-9 w-9 animate-spin" aria-hidden="true" />
            </div>
          ) : detail ? (
            <>
              <div className="grid gap-4 lg:grid-cols-2">
                <div className="rounded-2xl border border-border/50 bg-muted/30 p-5 shadow-sm">
                  <p className="mb-3 text-[11px] font-bold uppercase tracking-wider text-muted-foreground">
                    Doanh nghiệp
                  </p>
                  <div className="space-y-0">
                  <FieldRow label="Tên hiển thị" value={detail.businessName} />
                  <FieldRow label="Loại hình" value={typeLabel} />
                  <FieldRow label="Mã số thuế" value={detail.taxCode} mono />
                  <FieldRow
                    label="Số CCCD/CMND"
                    value={detail.idCardNumber}
                    mono
                  />
                  <FieldRow
                    label="Ngày gửi hồ sơ"
                    value={
                      detail.createdAt
                        ? new Date(detail.createdAt).toLocaleString("vi-VN")
                        : null
                    }
                  />
                  <FieldRow
                    label="Vận hành (địa điểm · DV · voucher · đặt chỗ)"
                    value={`${detail._count?.places ?? 0} · ${detail._count?.services ?? 0} · ${detail._count?.vouchers ?? 0} · ${detail._count?.bookings ?? 0}`}
                  />
                  </div>
                </div>

                <div className="rounded-2xl border border-border/50 bg-muted/30 p-5 shadow-sm">
                  <p className="mb-3 flex items-center gap-2 text-[11px] font-bold uppercase tracking-wider text-muted-foreground">
                    <span className="flex h-7 w-7 items-center justify-center rounded-xl bg-background shadow-sm">
                      <User className="h-3.5 w-3.5" aria-hidden="true" />
                    </span>
                    Chủ tài khoản & thanh toán
                  </p>
                  <div className="space-y-0">
                  <FieldRow label="Email" value={detail.owner?.email} />
                  <FieldRow label="Họ tên" value={detail.owner?.fullName} />
                  <FieldRow label="Ngân hàng" value={detail.bankName} />
                  <FieldRow
                    label="Số tài khoản"
                    value={detail.bankAccountNumber}
                    mono
                  />
                  <FieldRow label="Chủ TK" value={detail.bankAccountOwner} />
                  </div>
                </div>
              </div>

              <div className="rounded-2xl border border-border/50 bg-muted/20 p-5 shadow-sm">
                <p className="mb-3 flex items-center gap-2 text-[11px] font-bold uppercase tracking-wider text-muted-foreground">
                  <MapPin className="h-3.5 w-3.5" aria-hidden />
                  Địa điểm thuộc doanh nghiệp
                </p>
                {!Array.isArray(detail.places) || detail.places.length === 0 ? (
                  <p className="text-sm text-muted-foreground">
                    Chưa có địa điểm nào được gắn với hồ sơ này (có thể bổ sung
                    sau khi duyệt).
                  </p>
                ) : (
                  <ul className="space-y-2 max-h-[200px] overflow-y-auto pr-1">
                    {detail.places.map((p) => (
                      <li
                        key={p.id}
                        className="flex flex-wrap items-center justify-between gap-2 rounded-xl border border-border/40 bg-background/80 px-3 py-2 text-sm"
                      >
                        <span className="font-medium truncate">{p.name}</span>
                        <Link
                          to={ADMIN_ROUTES.PLACES_EDIT(p.id)}
                          className="inline-flex items-center gap-1 text-xs font-medium text-primary hover:underline shrink-0"
                          onClick={() => onOpenChange?.(false)}
                        >
                          Sửa
                          <ExternalLink className="h-3 w-3" />
                        </Link>
                      </li>
                    ))}
                  </ul>
                )}
              </div>

              <div className="space-y-4">
                <div className="flex flex-col gap-1 sm:flex-row sm:items-end sm:justify-between">
                  <div>
                    <p className="text-base font-semibold text-foreground">
                      Giấy tờ đính kèm
                    </p>
                    <p className="text-xs text-muted-foreground">
                      Thứ tự đối chiếu gợi ý: CCCD trước → sau → GPKD.
                    </p>
                  </div>
                </div>
                <div className="grid gap-5 sm:grid-cols-2 xl:grid-cols-3">
                  <DocumentPreviewCard
                    title="CCCD / CMND mặt trước"
                    raw={detail.idCardFront}
                  />
                  <DocumentPreviewCard
                    title="CCCD / CMND mặt sau"
                    raw={detail.idCardBack}
                  />
                  <DocumentPreviewCard
                    title="Giấy phép kinh doanh"
                    raw={detail.businessLicense}
                  />
                </div>
              </div>

              {!rejectMode ? (
                <>
                  <div className="rounded-2xl border border-border/50 bg-muted/25 p-5 shadow-sm space-y-3">
                    <Label
                      htmlFor="commission-rate"
                      className="text-sm font-medium"
                    >
                      Tỷ lệ hoa hồng nền tảng (%) sau khi duyệt
                    </Label>
                    <Input
                      id="commission-rate"
                      type="number"
                      min={0}
                      max={100}
                      step={0.5}
                      value={commissionRate}
                      onChange={(e) => setCommissionRate(e.target.value)}
                      className="max-w-[200px] rounded-xl border-border/60 font-mono"
                      autoComplete="off"
                    />
                    <p className="text-xs text-muted-foreground">
                      Áp dụng cho giao dịch trên nền tảng; có thể điều chỉnh
                      sau nếu cần.
                    </p>
                  </div>

                  <label className="flex cursor-pointer items-start gap-3 rounded-2xl border border-border/60 bg-background/50 p-4 transition-colors hover:bg-muted/40">
                    <Checkbox
                      checked={acknowledged}
                      onCheckedChange={(c) => setAcknowledged(Boolean(c))}
                      className="mt-0.5"
                      id="ack-compare"
                    />
                    <span className="text-sm leading-relaxed">
                      <span className="font-medium text-foreground">
                        Tôi đã đối chiếu
                      </span>{" "}
                      đủ 3 loại giấy tờ ở trên (ảnh hoặc PDF) với bản gốc hoặc
                      bản sao công chứng và{" "}
                      <strong>xác nhận khớp</strong> trước khi duyệt.
                    </span>
                  </label>
                </>
              ) : (
                <div className="space-y-2 rounded-2xl border border-destructive/20 bg-destructive/[0.03] p-4">
                  <Label htmlFor="reject-reason-admin" className="font-medium">
                    Lý do từ chối
                  </Label>
                  <Textarea
                    id="reject-reason-admin"
                    placeholder="Nêu rõ phần không khớp hoặc thiếu (tối thiểu 10 ký tự)…"
                    value={rejectReason}
                    onChange={(e) => setRejectReason(e.target.value)}
                    className="min-h-[120px] rounded-xl border-border/60"
                  />
                </div>
              )}
            </>
          ) : null}
        </div>

        <DialogFooter className="shrink-0 gap-2 rounded-b-3xl border-t border-border/40 bg-gradient-to-t from-muted/50 to-background p-4 sm:gap-3 sm:p-6 sm:pt-5">
          {!rejectMode ? (
            <>
              <Button
                type="button"
                variant="outline"
                onClick={() => onOpenChange?.(false)}
                disabled={submitting}
              >
                Đóng
              </Button>
              <Button
                type="button"
                variant="destructive"
                onClick={() => setRejectMode(true)}
                disabled={submitting || loading}
              >
                Từ chối hồ sơ
              </Button>
              <Button
                type="button"
                onClick={handleApprove}
                disabled={submitting || loading || !detail || !acknowledged}
                className="gap-1.5"
              >
                {submitting ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : null}
                Xác nhận duyệt
              </Button>
            </>
          ) : (
            <>
              <Button
                type="button"
                variant="outline"
                onClick={() => {
                  setRejectMode(false);
                  setRejectReason("");
                }}
                disabled={submitting}
              >
                Quay lại đối chiếu
              </Button>
              <Button
                type="button"
                variant="destructive"
                onClick={handleReject}
                disabled={submitting}
              >
                {submitting ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : null}
                Gửi từ chối
              </Button>
            </>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};

