const formatTrendValue = (trend) => {
  if (trend === undefined || trend === null || trend === "") return null;
  if (typeof trend === "number") {
    const sign = trend > 0 ? "+" : "";
    return `${sign}${trend}%`;
  }
  return String(trend);
};

