import { useState, useEffect } from "react";
import { X, Search } from "lucide-react";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Label } from "@/components/ui/Label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/Dialog";
import useCategoryStore from "@/stores/categoryStore";
import { useToast } from "@/hooks/use-toast";
import {
  CATEGORY_ICON_MAP,
  CATEGORY_ICON_PRESETS,
  CATEGORY_COLOR_PRESETS,
} from "@/constants/categoryConstants";

/**
 * CATEGORY FORM DIALOG
 * Form tạo/sửa danh mục
 */

export default function CategoryFormDialog({
  open,
  onClose,
  category,
  parentCategory,
}) {
  const { createCategory, updateCategory, fetchCategories } =
    useCategoryStore();
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);
  const [iconSearch, setIconSearch] = useState("");

  const [formData, setFormData] = useState({
    name: "",
    slug: "",
    icon: "",
    color: "#3B82F6",
    description: "",
    parentId: null,
    order: 0,
  });

  useEffect(() => {
    if (category) {
      // Edit mode
      setFormData({
        name: category.name || "",
        slug: category.slug || "",
        icon: category.icon || "",
        color: category.color || "#3B82F6",
        description: category.description || "",
        parentId: category.parentId || null,
        order: category.order || 0,
      });
    } else if (parentCategory) {
      // Add child mode
      setFormData({
        name: "",
        slug: "",
        icon: "",
        color: "#3B82F6",
        description: "",
        parentId: parentCategory.id,
        order: 0,
      });
    } else {
      // Add root mode
      setFormData({
        name: "",
        slug: "",
        icon: "",
        color: "#3B82F6",
        description: "",
        parentId: null,
        order: 0,
      });
    }
  }, [category, parentCategory, open]);

  const handleChange = (field, value) => {
    setFormData((prev) => {
      const updated = { ...prev, [field]: value };

      // Auto-generate slug from name
      if (field === "name" && !category) {
        updated.slug = value
          .toLowerCase()
          .normalize("NFD")
          .replace(/[\u0300-\u036f]/g, "")
          .replace(/đ/g, "d")
          .replace(/[^a-z0-9\s-]/g, "")
          .trim()
          .replace(/\s+/g, "-");
      }

      return updated;
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      if (category) {
        await updateCategory(category.id, formData);
        toast({
          title: "Thành công",
          description: "Cập nhật danh mục thành công",
        });
      } else {
        await createCategory(formData);
        toast({
          title: "Thành công",
          description: "Tạo danh mục thành công",
        });
      }
      await fetchCategories();
      onClose();
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Lỗi",
        description: error.response?.data?.message || error.message,
      });
    } finally {
      setLoading(false);
    }
  };

  const filteredIcons = CATEGORY_ICON_PRESETS.filter((icon) =>
    icon.toLowerCase().includes(iconSearch.toLowerCase()),
  );

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto rounded-none border border-black p-0 shadow-hard">
        <DialogHeader className="bg-black text-white p-6 border-b border-white/20">
          <DialogTitle className="text-xl font-black uppercase tracking-tight flex items-center justify-between">
            <span>
              {category
                ? "CHỈNH SỬA DANH MỤC"
                : parentCategory
                  ? "THÊM DANH MỤC CON"
                  : "TẠO DANH MỤC GỐC"}
            </span>
            <span className="text-[10px] font-mono bg-white text-black px-2 py-0.5">
              {category ? category.id.substring(0, 8) : "NEW"}
            </span>
          </DialogTitle>
          <DialogDescription className="text-gray-400 font-mono text-xs uppercase tracking-wider">
            {parentCategory
              ? `DIRECTORY PARENT: ${parentCategory.name}`
              : "ROOT DIRECTORY SYSTEM"}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="p-6 space-y-6 bg-white">
          {/* Tên & Slug */}
          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-2">
              <Label
                htmlFor="name"
                className="uppercase font-bold text-xs tracking-wider"
              >
                TÊN DANH MỤC <span className="text-red-500">*</span>
              </Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => handleChange("name", e.target.value)}
                placeholder="VD: TRÀ SỮA..."
                required
                className="rounded-none border-black font-mono text-sm focus-visible:ring-0 focus-visible:border-primary border-b-2 bg-gray-50 h-10"
              />
            </div>
            <div className="space-y-2">
              <Label
                htmlFor="slug"
                className="uppercase font-bold text-xs tracking-wider"
              >
                SLUG (URL) <span className="text-red-500">*</span>
              </Label>
              <Input
                id="slug"
                value={formData.slug}
                onChange={(e) => handleChange("slug", e.target.value)}
                placeholder="vd: tra-sua"
                required
                className="rounded-none border-black font-mono text-sm focus-visible:ring-0 bg-gray-50 h-10"
              />
            </div>
          </div>

          {/* Icon Picker */}
          <div className="space-y-3">
            <div className="flex justify-between items-center border-b border-black pb-2">
              <Label className="uppercase font-bold text-xs tracking-wider">
                ICON HIỂN THỊ
              </Label>
              <div className="flex items-center gap-2">
                <Search className="w-3 h-3" />
                <Input
                  placeholder="SEARCH ICON..."
                  value={iconSearch}
                  onChange={(e) => setIconSearch(e.target.value)}
                  className="h-6 w-32 rounded-none border-none border-b border-gray-200 text-xs font-mono uppercase bg-transparent p-0 focus-visible:ring-0"
                />
              </div>
            </div>

            <div className="grid grid-cols-6 sm:grid-cols-8 gap-2 max-h-[160px] overflow-y-auto p-2 border border-black bg-gray-50 scrollbar-thin">
              {filteredIcons.map((iconName) => {
                const IconComponent = CATEGORY_ICON_MAP[iconName];
                if (!IconComponent) return null;

                const isSelected = formData.icon === iconName;

                return (
                  <button
                    key={iconName}
                    type="button"
                    className={`
                        aspect-square flex items-center justify-center border transition-all
                        ${
                          isSelected
                            ? "bg-black text-white border-black shadow-none scale-90"
                            : "bg-white text-gray-500 border-gray-200 hover:border-black hover:text-black hover:shadow-hard"
                        }
                      `}
                    onClick={() => handleChange("icon", iconName)}
                    title={iconName}
                  >
                    <IconComponent className="h-5 w-5" />
                  </button>
                );
              })}
            </div>
          </div>

          {/* Color & Order */}
          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-2">
              <Label className="uppercase font-bold text-xs tracking-wider">
                MÃ MÀU
              </Label>
              <div className="flex items-center gap-2">
                <div
                  className="w-10 h-10 border border-black relative"
                  style={{ backgroundColor: formData.color }}
                >
                  <Input
                    type="color"
                    value={formData.color}
                    onChange={(e) => handleChange("color", e.target.value)}
                    className="absolute inset-0 opacity-0 cursor-pointer w-full h-full"
                  />
                </div>
                <Input
                  value={formData.color}
                  onChange={(e) => handleChange("color", e.target.value)}
                  className="flex-1 rounded-none border-black font-mono uppercase focus-visible:ring-0"
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label
                htmlFor="order"
                className="uppercase font-bold text-xs tracking-wider"
              >
                THỨ TỰ (PRIORITY)
              </Label>
              <Input
                id="order"
                type="number"
                value={formData.order}
                onChange={(e) =>
                  handleChange("order", parseInt(e.target.value))
                }
                min="0"
                className="rounded-none border-black font-mono focus-visible:ring-0"
              />
            </div>
          </div>

          {/* Mô tả */}
          <div className="space-y-2">
            <Label
              htmlFor="description"
              className="uppercase font-bold text-xs tracking-wider"
            >
              MÔ TẢ NGẮN
            </Label>
            <Textarea
              id="description"
              value={formData.description}
              onChange={(e) => handleChange("description", e.target.value)}
              placeholder="CHI TIẾT..."
              rows={3}
              className="rounded-none border-black font-mono focus-visible:ring-0 bg-gray-50"
            />
          </div>

          <DialogFooter className="border-t border-black pt-6 gap-3">
            <Button
              type="button"
              variant="outline"
              onClick={onClose}
              disabled={loading}
              className="rounded-none border-black hover:bg-gray-200 font-mono uppercase"
            >
              HỦY BỎ
            </Button>
            <Button
              type="submit"
              disabled={loading}
              className="rounded-none bg-black text-white hover:bg-primary hover:text-black hover:shadow-hard font-bold uppercase transition-all"
            >
              {loading
                ? "ĐANG XỬ LÝ..."
                : category
                  ? "LƯU THAY ĐỔI"
                  : "TẠO DANH MỤC"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { locationService } from "@/apis/locationService";

/**
 * ProvinceDistrictSelect Component
 *
 * Component chọn tỉnh/thành phố và phường/xã cho địa chỉ người dùng.
 * Sử dụng API: https://34tinhthanh.com/api
 *
 * Lưu ý: API mới (2025) trả về 2 cấp:
 * - Level 1: Province (34 tỉnh/thành sau sát nhập)
 * - Level 2: Ward (bao gồm cả quận/huyện và phường/xã)
 *
 * Do đó, dropdown "Quận/Huyện/Phường/Xã" sẽ hiển thị tất cả đơn vị hành chính
 * cấp dưới của tỉnh/thành phố đã chọn.
 */

const ProvinceDistrictSelect = ({
  provinceCode,
  districtCode,
  onProvinceChange,
  onDistrictChange,
  errors = {},
}) => {
  const [provinces, setProvinces] = useState([]);
  const [districts, setDistricts] = useState([]);
  const [loadingProvinces, setLoadingProvinces] = useState(true);
  const [loadingDistricts, setLoadingDistricts] = useState(false);

  // Load provinces on mount
  useEffect(() => {
    const fetchProvinces = async () => {
      try {
        const data = await locationService.getAllProvinces();
        setProvinces(data);
      } catch (error) {
        console.error("Failed to load provinces:", error);
      } finally {
        setLoadingProvinces(false);
      }
    };

    fetchProvinces();
  }, []);

  // Load districts when province changes
  useEffect(() => {
    if (!provinceCode) {
      setDistricts([]);
      return;
    }

    const fetchDistricts = async () => {
      setLoadingDistricts(true);
      try {
        // API mới trả về wards (bao gồm cả quận/huyện và phường/xã)
        const data = await locationService.getWardsByProvince(provinceCode);
        setDistricts(data);
      } catch (error) {
        console.error("Failed to load districts:", error);
      } finally {
        setLoadingDistricts(false);
      }
    };

    fetchDistricts();
  }, [provinceCode]);

  const handleProvinceChange = (e) => {
    const newProvinceCode = e.target.value;
    onProvinceChange(newProvinceCode);
    // Reset district when province changes
    onDistrictChange("");
  };

  const selectClassName =
    "w-full py-2.5 pl-10 pr-8 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm text-slate-700 dark:text-slate-300 focus:ring-blue-600 focus:border-blue-600 cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors appearance-none disabled:opacity-50 disabled:cursor-not-allowed";

  return (
    <div className="space-y-4">
      {/* Province Select */}
      <div>
        <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
          Tỉnh/Thành phố
        </label>
        <div className="relative">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none z-10">
            <span className="material-icons-round text-lg">location_city</span>
          </span>
          <select
            id="provinceCode"
            value={provinceCode || ""}
            onChange={handleProvinceChange}
            disabled={loadingProvinces}
            className={selectClassName}
          >
            <option value="">
              {loadingProvinces ? "Đang tải..." : "-- Chọn tỉnh/thành phố --"}
            </option>
            {provinces.map((province) => (
              <option
                key={province.province_code}
                value={province.province_code}
              >
                {province.name}
              </option>
            ))}
          </select>
          <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">
            <span className="material-icons-round text-lg">expand_more</span>
          </span>
        </div>
        {errors.provinceCode && (
          <p className="text-sm text-red-500 mt-1 flex items-center gap-1">
            <span className="material-icons-round text-sm">error</span>
            {errors.provinceCode}
          </p>
        )}
      </div>

      {/* District Select */}
      <div>
        <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
          Quận/Huyện/Phường/Xã
        </label>
        <div className="relative">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none z-10">
            <span className="material-icons-round text-lg">map</span>
          </span>
          <select
            id="districtCode"
            value={districtCode || ""}
            onChange={(e) => onDistrictChange(e.target.value)}
            disabled={
              !provinceCode || loadingDistricts || districts.length === 0
            }
            className={selectClassName}
          >
            <option value="">
              {loadingDistricts
                ? "Đang tải..."
                : !provinceCode
                ? "Vui lòng chọn tỉnh/thành phố trước"
                : "-- Chọn quận/huyện/phường/xã --"}
            </option>
            {districts.map((district) => (
              <option key={district.ward_code} value={district.ward_code}>
                {district.ward_name}
              </option>
            ))}
          </select>
          <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">
            <span className="material-icons-round text-lg">expand_more</span>
          </span>
        </div>
        {errors.districtCode && (
          <p className="text-sm text-red-500 mt-1 flex items-center gap-1">
            <span className="material-icons-round text-sm">error</span>
            {errors.districtCode}
          </p>
        )}
      </div>
    </div>
  );
};

export default ProvinceDistrictSelect;

import { useState } from "react";
import {
  Plus,
  Trash2,
  Clock,
  Calendar,
  Copy,
  CheckCircle2,
  AlertCircle,
} from "lucide-react";
import {
  Button,
  Label,
  Input,
  Checkbox,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui";
import { DAYS_OF_WEEK } from "@/constants/placeConstants";
import { cn } from "@/lib/utils";

/**
 * OPENING HOURS EDITOR - T.I.M STYLE (VIETNAMESE)
 * Technical Industrial Minimalism Design
 * Component để quản lý giờ mở cửa theo từng ngày trong tuần
 */

// Map server format to display format
const DAYS_MAP = DAYS_OF_WEEK.map((day, index) => ({
  value: (index + 1) % 7, // 0: Sunday, 1: Monday, ... 6: Saturday
  label: day.label,
  short: day.label.replace("Thứ ", "T").replace("Chủ Nhật", "CN"),
}));

const OpeningHoursEditor = ({ value = [], onChange }) => {
  const [is24Hours, setIs24Hours] = useState(false);

  // Auto-migrate legacy data (7 -> 0 for Sunday)
  if (value.some((slot) => slot.dayOfWeek === 7)) {
    const migrated = value.map((slot) => ({
      ...slot,
      dayOfWeek: slot.dayOfWeek === 7 ? 0 : slot.dayOfWeek,
    }));
    // Use setTimeout to avoid render-cycle state updates
    setTimeout(() => onChange(migrated), 0);
  }

  const handleAddSlot = () => {
    // Find missing days or defaulting to the next day in sequence
    let nextDay = 1; // Default to Monday
    if (value.length > 0) {
      const lastDay = value[value.length - 1].dayOfWeek;
      // Logic: 1->2...->6->0->1
      nextDay = lastDay === 6 ? 0 : lastDay === 0 ? 1 : lastDay + 1;
    }

    const newSlot = {
      dayOfWeek: nextDay,
      openTime: "09:00",
      closeTime: "22:00",
      isClosed: false,
    };
    onChange([...value, newSlot]);
  };

  const handleUpdateSlot = (index, field, newValue) => {
    const newSlots = [...value];
    newSlots[index] = { ...newSlots[index], [field]: newValue };
    onChange(newSlots);
  };

  const handleRemoveSlot = (index) => {
    const newSlots = value.filter((_, i) => i !== index);
    onChange(newSlots);
  };

  const handleApplyToAllDays = () => {
    if (value.length === 0) {
      alert("LỖI: CHƯA CÓ DỮ LIỆU MẪU. Vui lòng thêm một khung giờ trước.");
      return;
    }

    const template = value[0];
    const newSlots = DAYS_MAP.map((day) => ({
      dayOfWeek: day.value, // Using the mapped value index
      openTime: template.openTime,
      closeTime: template.closeTime,
      isClosed: template.isClosed,
    }));
    onChange(newSlots);
  };

  const handleSet24Hours = (checked) => {
    setIs24Hours(checked);
    if (checked) {
      const newSlots = DAYS_MAP.map((day) => ({
        dayOfWeek: day.value,
        openTime: "00:00",
        closeTime: "23:59",
        isClosed: false,
      }));
      onChange(newSlots);
    }
  };

  return (
    <div className="space-y-4">
      {/* Header Panel */}
      <div className="flex items-center justify-between border-b border-gray-200 pb-2">
        <div className="flex items-center gap-2">
          <Clock className="w-5 h-5 text-gray-500" />
          <Label className="text-base font-bold font-mono uppercase tracking-wider">
            Thời gian mở cửa
          </Label>
        </div>
        <div className="flex items-center gap-2">
          {!is24Hours && (
            <Button
              type="button"
              variant="outline"
              size="sm"
              onClick={handleAddSlot}
              className="h-8 border-dashed border-gray-400 hover:border-blue-500 font-mono text-xs uppercase"
            >
              <Plus className="mr-2 h-3 w-3" />
              THÊM_KHUNG_GIỜ
            </Button>
          )}
        </div>
      </div>

      {/* Control Panel */}
      <div className="flex items-center justify-between bg-gray-50 p-3 rounded-sm border border-gray-200">
        <div className="flex items-center space-x-2">
          <Checkbox
            id="24hours"
            checked={is24Hours}
            onCheckedChange={handleSet24Hours}
            className="rounded-sm data-[state=checked]:bg-emerald-500 data-[state=checked]:border-emerald-500"
          />
          <label
            htmlFor="24hours"
            className="text-sm font-bold font-mono cursor-pointer uppercase text-gray-700"
          >
            CHẾ ĐỘ: 24/7
          </label>
        </div>

        {!is24Hours && (
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={handleApplyToAllDays}
            disabled={value.length === 0}
            className="h-7 text-xs font-mono text-blue-600 hover:text-blue-700 hover:bg-blue-50"
          >
            <Copy className="mr-2 h-3 w-3" />
            ĐỒNG_BỘ_TẤT_CẢ
          </Button>
        )}
      </div>

      {/* Schedule Matrix */}
      {value.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-10 border-2 border-dashed border-gray-300 rounded-sm bg-gray-50/50">
          <Calendar className="h-10 w-10 mb-3 text-gray-300" />
          <p className="text-sm font-mono text-gray-400 uppercase">
            CHƯA_CÓ_LỊCH_HOẠT_ĐỘNG
          </p>
          <p className="text-xs text-gray-400 mt-1">
            [ Nhấn THÊM_KHUNG_GIỜ để thiết lập ]
          </p>
        </div>
      ) : (
        <div className="border border-gray-200 rounded-sm overflow-hidden">
          {/* Table Header */}
          <div className="grid grid-cols-12 gap-4 bg-black p-2 border-b border-black text-[10px] font-mono font-bold text-white uppercase">
            <div className="col-span-3 pl-2">THỨ</div>
            <div className="col-span-2 text-center">TRẠNG THÁI</div>
            <div className="col-span-6 text-center">KHUNG GIỜ (GIỜ:PHÚT)</div>
            <div className="col-span-1"></div>
          </div>

          {/* Rows */}
          <div className="divide-y divide-gray-100 bg-white">
            {value.map((slot, index) => (
              <div
                key={index}
                className={cn(
                  "grid grid-cols-12 gap-4 p-2 items-center hover:bg-gray-50 transition-colors group",
                  slot.isClosed ? "bg-red-50/20" : "",
                )}
              >
                {/* Day Selector */}
                <div className="col-span-3">
                  <Select
                    value={slot.dayOfWeek.toString()}
                    onValueChange={(val) =>
                      handleUpdateSlot(index, "dayOfWeek", parseInt(val))
                    }
                    disabled={is24Hours}
                  >
                    <SelectTrigger className="h-8 text-xs font-mono border-gray-200 focus:ring-0 focus:border-blue-500 bg-white">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {DAYS_MAP.map((day) => (
                        <SelectItem
                          key={day.value}
                          value={day.value.toString()}
                          className="font-mono text-xs"
                        >
                          <span className="font-bold mr-2">{day.short}</span>
                          <span className="text-gray-400">{day.label}</span>
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                {/* Status Toggle - Increased gap via grid gap-4 */}
                <div className="col-span-2 flex justify-center">
                  <div
                    className={cn(
                      "cursor-pointer px-2 py-1 rounded-sm border text-[10px] font-mono font-bold uppercase transition-all w-full text-center hover:opacity-80 select-none",
                      slot.isClosed
                        ? "bg-red-100 text-red-600 border-red-200"
                        : "bg-emerald-100 text-emerald-600 border-emerald-200",
                    )}
                    onClick={() =>
                      !is24Hours &&
                      handleUpdateSlot(index, "isClosed", !slot.isClosed)
                    }
                  >
                    {slot.isClosed ? "ĐÓNG" : "MỞ"}
                  </div>
                </div>

                {/* Time Inputs */}
                <div className="col-span-6 flex items-center gap-4 justify-center">
                  {!slot.isClosed ? (
                    <>
                      <Input
                        type="time"
                        value={slot.openTime || ""}
                        onChange={(e) =>
                          handleUpdateSlot(index, "openTime", e.target.value)
                        }
                        disabled={is24Hours}
                        className="h-8 w-28 text-xs font-mono text-center border-gray-200 focus-visible:ring-0 focus-visible:border-blue-500 px-1"
                      />
                      <span className="text-gray-300 font-mono">-</span>
                      <Input
                        type="time"
                        value={slot.closeTime || ""}
                        onChange={(e) =>
                          handleUpdateSlot(index, "closeTime", e.target.value)
                        }
                        disabled={is24Hours}
                        className="h-8 w-28 text-xs font-mono text-center border-gray-200 focus-visible:ring-0 focus-visible:border-blue-500 px-1"
                      />
                    </>
                  ) : (
                    <div className="text-xs text-gray-400 font-mono italic flex items-center justify-center w-full bg-gray-50 h-8 rounded-sm border border-transparent">
                      -- KHÔNG HOẠT ĐỘNG --
                    </div>
                  )}
                </div>

                {/* Actions */}
                <div className="col-span-1 flex justify-end">
                  {!is24Hours && (
                    <Button
                      type="button"
                      variant="ghost"
                      size="sm"
                      onClick={() => handleRemoveSlot(index)}
                      className="h-8 w-8 p-0 text-gray-400 hover:text-red-500 hover:bg-red-50 opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Footer Info */}
      <div className="flex items-center gap-2 text-[10px] text-gray-400 font-mono pt-1">
        <AlertCircle className="w-3 h-3" />
        <span>
          THÔNG TIN HỆ THỐNG:{" "}
          {is24Hours
            ? "GHI ĐÈ KÍCH HOẠT [24/7]"
            : `${value.length} KHUNG GIỜ ĐÃ CẤU HÌNH`}
        </span>
      </div>
    </div>
  );
};

export default OpeningHoursEditor;

