      </div>
      <span className="text-sm text-gray-700 leading-snug">{children}</span>
    </div>
  );
  if (href) {
    return (
      <a
        href={href}
        target={href.startsWith("http") ? "_blank" : "_self"}
        rel="noreferrer"
        className="hover:opacity-80 transition-opacity"
      >
        {inner}
      </a>
    );
  }
  return inner;
}

