                          <InfoChip icon={Facebook} href={facebook}>
                            <span className="text-blue-600 flex items-center gap-1 truncate">
                              {facebook.replace(
                                /^https?:\/\/(www\.)?facebook\.com\//,
                                "fb/",
                              )}
                              <ArrowUpRight className="w-3.5 h-3.5 shrink-0" />
                            </span>
                          </InfoChip>
                        )}
                      </div>
                    </div>
                  </>
                )}

                {/* ═══ HOURS ═══ */}
                {activeTab === "hours" && (
                  <>
                    {/* Open/closed banner */}
                    {openStatus.known && (
                      <div
                        className={cn(
                          "flex items-start gap-4 p-5 rounded-2xl border",
                          openStatus.open
                            ? "bg-emerald-50 border-emerald-200"
                            : "bg-red-50 border-red-200",
                        )}
                      >
                        <span
                          className={cn(
                            "w-3 h-3 rounded-full mt-1 shrink-0",
                            openStatus.open
                              ? "bg-emerald-500 animate-pulse"
                              : "bg-red-400",
                          )}
                        />
                        <div>
                          <p
                            className={cn(
                              "font-black text-base",
                              openStatus.open
                                ? "text-emerald-800"
                                : "text-red-700",
                            )}
                          >
                            {openStatus.open
                              ? "Hiện đang mở cửa"
                              : "Hiện đã đóng cửa"}
                          </p>
                          {openStatus.todayHour &&
                            !openStatus.todayHour.isClosed && (
                              <p className="text-sm text-gray-500 mt-0.5">
                                {DAY_FULL[new Date().getDay()]}:{" "}
                                <span className="font-bold text-gray-800">
                                  {openStatus.todayHour.openTime?.slice(0, 5)} –{" "}
                                  {openStatus.todayHour.closeTime?.slice(0, 5)}
                                </span>
                              </p>
                            )}
                          {openStatus.todayHour?.isClosed && (
                            <p className="text-sm text-gray-500 mt-0.5">
                              Hôm nay ({DAY_FULL[new Date().getDay()]}) đóng cửa
                            </p>
                          )}
                        </div>
                      </div>
                    )}

                    {/* Hours list */}
                    {place.openingHours?.length > 0 ? (
                      <div>
                        <SectionTitle icon={Clock}>Lịch hoạt động</SectionTitle>
                        <div className="space-y-1.5">
                          {[...place.openingHours]
                            .sort((a, b) => {
                              const da = a.dayOfWeek === 0 ? 7 : a.dayOfWeek;
                              const db = b.dayOfWeek === 0 ? 7 : b.dayOfWeek;
                              return da - db;
                            })
                            .map((h, i) => {
                              const isToday =
                                h.dayOfWeek === new Date().getDay();
                              return (
                                <div
                                  key={i}
                                  className={cn(
                                    "flex items-center justify-between px-4 py-3 rounded-xl transition-colors",
                                    isToday
                                      ? "bg-gray-900 text-white"
                                      : "bg-gray-50 hover:bg-gray-100",
                                  )}
                                >
                                  <div className="flex items-center gap-3">
                                    <span
                                      className={cn(
                                        "w-7 text-xs font-black uppercase",
                                        isToday
                                          ? "text-yellow-400"
                                          : "text-gray-400",
                                      )}
                                    >
                                      {DAY_SHORT[h.dayOfWeek]}
                                    </span>
                                    <span
                                      className={cn(
                                        "text-sm font-semibold",
                                        isToday
                                          ? "text-white"
                                          : "text-gray-700",
                                      )}
                                    >
                                      {DAY_FULL[h.dayOfWeek]}
                                    </span>
                                    {isToday && (
                                      <span className="text-[9px] bg-yellow-400 text-yellow-950 font-black px-2 py-0.5 rounded-full">
                                        HÔM NAY
                                      </span>
                                    )}
                                  </div>
                                  <span
                                    className={cn(
                                      "text-sm font-bold",
                                      h.isClosed
                                        ? isToday
                                          ? "text-red-400"
                                          : "text-red-500"
                                        : isToday
                                          ? "text-emerald-300"
                                          : "text-gray-800",
                                    )}
                                  >
                                    {h.isClosed
                                      ? "Đóng cửa"
                                      : `${h.openTime?.slice(0, 5)} – ${h.closeTime?.slice(0, 5)}`}
                                  </span>
                                </div>
                              );
                            })}
                        </div>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center justify-center py-20 text-gray-400">
                        <Clock className="w-14 h-14 mb-4 opacity-15" />
                        <p className="text-sm font-semibold">
                          Chưa cập nhật giờ hoạt động
                        </p>
                      </div>
                    )}
                  </>
                )}

                {/* ═══ LOCATION ═══ */}
                {activeTab === "location" && (
                  <>
                    {place.latitude && place.longitude ? (
                      <>
                        {/* Map */}
                        <div className="rounded-2xl overflow-hidden border border-gray-200 shadow-sm">
                          <div className="h-[280px]">
                            <MapView
                              places={[place]}
                              showMarkers
                              interactive
                              initialViewState={{
                                latitude: Number(place.latitude),
                                longitude: Number(place.longitude),
                                zoom: 15,
                              }}
                            />
                          </div>
                          <div className="bg-gray-900 px-5 py-3 flex items-center justify-between">
                            <div className="flex items-center gap-2 text-sm font-mono">
                              <MapPin className="w-4 h-4 text-gray-500" />
                              <span className="text-white font-bold">
                                {Number(place.latitude).toFixed(6)}
                              </span>
                              <span className="text-gray-600">,</span>
                              <span className="text-white font-bold">
                                {Number(place.longitude).toFixed(6)}
                              </span>
                            </div>
                            <a
                              href={`https://www.google.com/maps/search/?api=1&query=${place.latitude},${place.longitude}`}
                              target="_blank"
                              rel="noreferrer"
                              className="flex items-center gap-1.5 text-[12px] font-bold text-emerald-400 hover:text-emerald-300 transition-colors"
                            >
                              Mở Google Maps{" "}
                              <ArrowUpRight className="w-3.5 h-3.5" />
                            </a>
                          </div>
                        </div>

                        {/* Address breakdown */}
                        <div>
                          <SectionTitle icon={Navigation}>
                            Địa chỉ đầy đủ
                          </SectionTitle>
                          <div className="space-y-3">
                            {place.address && (
                              <InfoChip icon={MapPin}>{place.address}</InfoChip>
                            )}
                            {place.ward && (
                              <InfoChip icon={Building2}>
                                <span className="text-gray-400 text-xs mr-1">
                                  Phường/Xã:
                                </span>
                                {place.ward.name}
                              </InfoChip>
                            )}
                            {place.district && (
                              <InfoChip icon={Navigation}>
                                <span className="text-gray-400 text-xs mr-1">
                                  Quận/Huyện:
                                </span>
                                {place.district.name}
                              </InfoChip>
                            )}
                            <InfoChip icon={MapPin}>
                              <span className="text-gray-400 text-xs mr-1">
                                Tọa độ:
                              </span>
                              <span className="font-mono">
                                {Number(place.latitude).toFixed(6)},{" "}
                                {Number(place.longitude).toFixed(6)}
                              </span>
                            </InfoChip>
                          </div>
                        </div>
                      </>
                    ) : (
                      <div className="flex flex-col items-center justify-center py-20 text-gray-400">
                        <MapPin className="w-14 h-14 mb-4 opacity-15" />
                        <p className="text-sm font-semibold">
                          Chưa có thông tin vị trí
                        </p>
                      </div>
                    )}
                  </>
                )}

                {/* ═══ DETAILS ═══ */}
                {activeTab === "details" && (
                  <>
                    {/* Amenities */}
                    {hasAmenities && (
                      <div>
                        <SectionTitle icon={CheckCircle}>Tiện ích</SectionTitle>
                        <div className="flex flex-wrap gap-2">
                          {place.amenities.map((a, i) => (
                            <div
                              key={i}
                              className="flex items-center gap-1.5 px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-[12px] font-medium text-gray-700 hover:border-gray-400 transition-colors"
                            >
                              <CheckCircle className="w-3.5 h-3.5 text-emerald-500 shrink-0" />
                              <span className="font-bold">{a.amenityType}</span>
                              {a.amenityValue && (
                                <span className="text-gray-400">
                                  · {a.amenityValue}
                                </span>
                              )}
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                    {/* Tags */}
                    {hasTags && (
                      <div>
                        <SectionTitle icon={Hash}>Thẻ (Tags)</SectionTitle>
                        <div className="flex flex-wrap gap-2">
                          {tagList.map((tag, i) => (
                            <span
                              key={i}
                              className="inline-flex items-center gap-1 px-3 py-1.5 bg-gray-900 text-white text-[12px] font-bold rounded-xl hover:bg-gray-700 transition-colors"
                            >
                              <Hash className="w-3 h-3" />
                              {tag.name}
                            </span>
                          ))}
                        </div>
                      </div>
                    )}

                    {/* System info */}
                    <div>
                      <SectionTitle icon={TrendingUp}>
                        Thông tin hệ thống
                      </SectionTitle>
                      <div className="bg-gray-50 rounded-2xl p-5 space-y-2.5 border border-gray-100">
                        {[
                          { label: "ID", value: `#${place.id}` },
                          { label: "Slug", value: place.slug || "—" },
                          {
                            label: "Trạng thái",
                            value:
                              STATUS_CFG[place.status]?.label || place.status,
                          },
                          {
                            label: "Ngày tạo",
                            value: place.createdAt
                              ? new Date(place.createdAt).toLocaleString(
                                  "vi-VN",
                                )
                              : "—",
                          },
                          {
                            label: "Cập nhật",
                            value: place.updatedAt
                              ? new Date(place.updatedAt).toLocaleString(
                                  "vi-VN",
                                )
                              : "—",
                          },
                          {
                            label: "Lượt xem",
                            value: (place.viewCount || 0).toLocaleString(),
                          },
                          {
                            label: "Tổng đánh giá",
                            value: `${place.ratingCount || 0} đánh giá · TB ${rating.toFixed(1)}/5`,
                          },
                        ].map(({ label, value }) => (
                          <div
                            key={label}
                            className="flex items-center justify-between py-1.5 border-b border-gray-100 last:border-0"
                          >
                            <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">
                              {label}
                            </span>
                            <span className="text-[12px] font-mono font-semibold text-gray-800">
                              {value}
                            </span>
                          </div>
                        ))}
                      </div>
                    </div>

                    {/* Rejection reason */}
                    {place.status === "rejected" && place.rejectionReason && (
                      <div className="p-5 bg-red-50 border border-red-200 rounded-2xl">
                        <p className="text-[11px] font-bold text-red-500 uppercase tracking-widest mb-2">
                          Lý do từ chối
                        </p>
                        <p className="text-sm text-red-700 leading-relaxed">
                          {place.rejectionReason}
                        </p>
                      </div>
                    )}
                  </>
                )}
              </div>
            </ScrollArea>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default PlaceDetailDialog;

import { useState, useEffect, useMemo, useCallback } from "react";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/Label";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Progress } from "@/components/ui/progress";
import { Badge } from "@/components/ui/badge";
import { PermissionCheckbox } from "./permission-checkbox";
import { roleService } from "@/apis/roleService";
import { permissionService } from "@/apis/permissionService";
import { MODULE_DISPLAY_NAMES } from "@/constants/permissions";
import { toast } from "sonner";
import { cn } from "@/lib/utils";
import {
  Search,
  CheckCircle,
  XCircle,
  ChevronDown,
  Save,
  RefreshCw,
  SearchX,
} from "lucide-react";

export function RolePermissionTab({ role, onUpdated, onClose }) {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [allPermissions, setAllPermissions] = useState({});
  const [selectedPermissions, setSelectedPermissions] = useState(new Set());
  const [initialPermissions, setInitialPermissions] = useState(new Set());
  const [search, setSearch] = useState("");
  const [moduleFilter, setModuleFilter] = useState("all");
  const [expandedModules, setExpandedModules] = useState(new Set());

  const fetchData = useCallback(async () => {
    try {
      setLoading(true);

      const [permissionsResponse, rolePermissionsResponse] = await Promise.all([
        permissionService.getPermissionsByModule(false),
        roleService.getRolePermissions(role.id),
      ]);

      if (permissionsResponse?.success && permissionsResponse.permissions) {
        setAllPermissions(permissionsResponse.permissions);

        const currentPermissionIds = new Set();
        if (
          rolePermissionsResponse?.success &&
          rolePermissionsResponse.data?.permissions
        ) {
          Object.values(rolePermissionsResponse.data.permissions).forEach(
            (perms) => {
              perms.forEach((p) => currentPermissionIds.add(p.id));
            },
          );
        }

        setSelectedPermissions(currentPermissionIds);
        setInitialPermissions(currentPermissionIds);

        const modules = Object.keys(permissionsResponse.permissions);
        setExpandedModules(new Set(modules.slice(0, 3)));
      }
    } catch (error) {
      const errorMsg =
        error.response?.data?.message ||
        error.message ||
        "Không thể tải danh sách quyền";
      toast.error(errorMsg);
    } finally {
      setLoading(false);
    }
  }, [role?.id]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleTogglePermission = (permissionId) => {
    setSelectedPermissions((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(permissionId)) {
        newSet.delete(permissionId);
      } else {
        newSet.add(permissionId);
      }
      return newSet;
    });
  };

  const handleSelectAll = () => {
    const allIds = new Set();
    Object.values(filteredPermissions).forEach((perms) => {
      perms.forEach((p) => allIds.add(p.id));
    });
    setSelectedPermissions(allIds);
  };

  const handleDeselectAll = () => {
    setSelectedPermissions(new Set());
  };

  const handleToggleModule = (module) => {
    const modulePermissions = filteredPermissions[module] || [];
    const moduleIds = modulePermissions.map((p) => p.id);
    const allSelected = moduleIds.every((id) => selectedPermissions.has(id));

    setSelectedPermissions((prev) => {
      const newSet = new Set(prev);
      if (allSelected) {
        moduleIds.forEach((id) => newSet.delete(id));
      } else {
        moduleIds.forEach((id) => newSet.add(id));
      }
      return newSet;
    });
  };

  const handleSave = async () => {
    try {
      setSaving(true);
      const permissionIds = Array.from(selectedPermissions);

      const response = await roleService.updateRolePermissions(
        role.id,
        permissionIds,
      );

      if (response?.success) {
        toast.success(response.message || "Cập nhật quyền thành công");
        setInitialPermissions(new Set(selectedPermissions));

        if (onUpdated) {
          onUpdated();
        }

        onClose();
      }
    } catch (error) {
      const errorMsg =
        error.response?.data?.message ||
        error.message ||
        "Không thể cập nhật quyền";
      toast.error(errorMsg);
    } finally {
      setSaving(false);
    }
  };

  const filteredPermissions = useMemo(() => {
    let result = { ...allPermissions };

    if (moduleFilter !== "all") {
      result = { [moduleFilter]: allPermissions[moduleFilter] || [] };
    }

    if (search.trim()) {
      const lowerSearch = search.toLowerCase();
      const filtered = {};

      Object.entries(result).forEach(([module, perms]) => {
        const matched = perms.filter(
          (p) =>
            p.name.toLowerCase().includes(lowerSearch) ||
            p.displayName.toLowerCase().includes(lowerSearch),
        );
        if (matched.length > 0) {
          filtered[module] = matched;
        }
      });

      result = filtered;
    }

    return result;
  }, [allPermissions, moduleFilter, search]);

  const stats = useMemo(() => {
    let totalFiltered = 0;
    let selectedFiltered = 0;

    Object.values(filteredPermissions).forEach((perms) => {
      totalFiltered += perms.length;
      selectedFiltered += perms.filter((p) =>
        selectedPermissions.has(p.id),
      ).length;
    });

    return {
      total: totalFiltered,
      selected: selectedFiltered,
      percentage:
        totalFiltered > 0 ? (selectedFiltered / totalFiltered) * 100 : 0,
    };
  }, [filteredPermissions, selectedPermissions]);

  const hasChanges = useMemo(() => {
    if (selectedPermissions.size !== initialPermissions.size) return true;
    for (const id of selectedPermissions) {
      if (!initialPermissions.has(id)) return true;
    }
    return false;
  }, [selectedPermissions, initialPermissions]);

  const toggleModuleExpand = (module) => {
    setExpandedModules((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(module)) {
        newSet.delete(module);
      } else {
        newSet.add(module);
      }
      return newSet;
    });
  };

  if (loading) {
    return (
      <div className="space-y-4 py-4">
        <Skeleton className="h-10 w-full border border-black" />
        <Skeleton className="h-10 w-full border border-black" />
        <Skeleton className="h-40 w-full border border-black" />
        <Skeleton className="h-40 w-full border border-black" />
      </div>
    );
  }

  return (
    <div className="space-y-4 pb-4">
      {/* Search and Filter */}
      <div className="flex flex-col sm:flex-row items-center gap-3">
        <div className="relative flex-1 w-full">
          <div className="absolute left-0 top-0 h-full w-10 bg-black flex items-center justify-center text-white">
            <Search className="h-4 w-4" />
          </div>
          <Input
            placeholder="TÌM KIẾM QUYỀN..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-12 h-10 rounded-none border border-black bg-white focus-visible:ring-0 focus-visible:border-black focus:bg-yellow-50 uppercase text-xs font-mono"
          />
        </div>
        <Select value={moduleFilter} onValueChange={setModuleFilter}>
          <SelectTrigger className="w-full sm:w-[200px] h-10 rounded-none border border-black bg-white uppercase text-xs font-bold">
            <SelectValue placeholder="LỌC MODULE" />
          </SelectTrigger>
          <SelectContent className="rounded-none border-2 border-black bg-white">
            <SelectItem value="all" className="uppercase font-mono text-xs">
              TẤT CẢ MODULES
            </SelectItem>
            {Object.keys(allPermissions).map((module) => (
              <SelectItem
                key={module}
                value={module}
                className="uppercase font-mono text-xs"
              >
                {MODULE_DISPLAY_NAMES[module] || module}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      {/* Progress and Actions */}
      <div className="bg-white p-4 border border-black flex flex-col sm:flex-row items-center justify-between gap-4">
        <div className="space-y-2 w-full sm:w-auto">
          <div className="flex items-center justify-between sm:justify-start gap-3 text-xs font-bold text-black uppercase tracking-wider">
            <span className="font-mono">
              ĐÃ CHỌN: {stats.selected} / {stats.total}
            </span>
            <span className="bg-[#F3E600] text-black px-2 py-0.5 font-mono">
              {Math.round(stats.percentage)}%
            </span>
          </div>
          <div className="w-full sm:w-[240px] h-1 bg-gray-200 border border-gray-300">
            <div
              className="h-full bg-[#F3E600] transition-all duration-300"
              style={{ width: `${stats.percentage}%` }}
            />
          </div>
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <Button
            variant="outline"
            size="sm"
            onClick={handleSelectAll}
            disabled={stats.selected === stats.total}
            className="flex-1 sm:flex-none rounded-none border border-black hover:bg-black hover:text-white uppercase text-xs font-bold"
          >
            <CheckCircle className="h-3 w-3 mr-2" />
            CHỌN TẤT
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={handleDeselectAll}
            disabled={stats.selected === 0}
            className="flex-1 sm:flex-none rounded-none border border-black hover:bg-black hover:text-white uppercase text-xs font-bold"
          >
            <XCircle className="h-3 w-3 mr-2" />
            BỎ CHỌN
          </Button>
        </div>
      </div>

      {/* Permissions List */}
      <div className="space-y-3">
        {Object.keys(filteredPermissions).length === 0 ? (
          <div className="text-center py-12 text-gray-500 bg-white border border-black border-dashed">
            <SearchX className="h-12 w-12 mx-auto mb-2 opacity-30" />
            <p className="uppercase font-mono text-xs">KHÔNG TÌM THẤY QUYỀN</p>
          </div>
        ) : (
          Object.entries(filteredPermissions).map(([module, permissions]) => {
            const moduleSelected = permissions.filter((p) =>
              selectedPermissions.has(p.id),
            ).length;
            const moduleTotal = permissions.length;
            const isExpanded = expandedModules.has(module);

            return (
              <div
                key={module}
                className="border border-black overflow-hidden transition-all hover:shadow-hard"
              >
                <div
                  className="flex items-center justify-between p-4 bg-white cursor-pointer select-none hover:bg-gray-50 border-l-4 border-l-transparent hover:border-l-[#F3E600] transition-all"
                  onClick={() => toggleModuleExpand(module)}
                >
                  <div className="flex items-center gap-3">
                    <div onClick={(e) => e.stopPropagation()}>
                      <Checkbox
                        checked={
                          moduleSelected === moduleTotal && moduleTotal > 0
                            ? true
                            : moduleSelected > 0
                              ? "indeterminate"
                              : false
                        }
                        onCheckedChange={() => handleToggleModule(module)}
                        className="data-[state=checked]:bg-[#F3E600] data-[state=checked]:border-black data-[state=checked]:text-black rounded-none border-2"
                      />
                    </div>
                    <div className="flex items-center gap-3">
                      <div className="h-8 w-1 bg-black"></div>
                      <div>
                        <Label className="font-bold text-black text-sm cursor-pointer uppercase tracking-tight">
                          {MODULE_DISPLAY_NAMES[module] || module}
                        </Label>
                        <p className="text-xs text-gray-500 font-mono mt-0.5 uppercase">
                          {moduleSelected}/{moduleTotal} QUYỀN
                        </p>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                    <Badge
                      variant="secondary"
                      className="bg-black text-white rounded-none px-2.5 py-1 font-mono text-xs uppercase"
                    >
                      {module}
                    </Badge>
                    <ChevronDown
                      className={cn(
                        "h-4 w-4 text-black transition-transform duration-200",
                        isExpanded ? "rotate-180" : "",
                      )}
                    />
                  </div>
                </div>

                {isExpanded && (
                  <div className="p-4 space-y-2 bg-gray-50 border-t-2 border-black">
                    {permissions.map((permission) => (
                      <PermissionCheckbox
                        key={permission.id}
                        permission={permission}
                        checked={selectedPermissions.has(permission.id)}
                        onCheckedChange={() =>
                          handleTogglePermission(permission.id)
                        }
                      />
                    ))}
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>

      {/* Footer Actions */}
      <div className="flex justify-end gap-3 pt-4 mt-6 border-t-2 border-black sticky bottom-0 bg-white p-4 -mx-4 -mb-4 shadow-hard z-10 sm:static sm:bg-transparent sm:p-0 sm:shadow-none">
        <Button
          variant="outline"
          onClick={onClose}
          className="rounded-none border border-black hover:bg-gray-100 uppercase text-xs font-bold"
        >
          HỦY
        </Button>
        <Button
          onClick={handleSave}
          disabled={!hasChanges || saving}
          className="rounded-none bg-black hover:bg-[#F3E600] hover:text-black text-white border border-black shadow-hard uppercase text-xs font-bold"
        >
          {saving ? (
            <span className="flex items-center gap-2">
              <RefreshCw className="h-3 w-3 animate-spin" />
              ĐANG LƯU...
            </span>
          ) : (
            <span className="flex items-center gap-2">
              <Save className="h-3 w-3" />
              LƯU THAY ĐỔI
            </span>
          )}
        </Button>
      </div>
    </div>
  );
}

import { useState, useEffect, useMemo, useCallback } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/Dialog";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/Label";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Progress } from "@/components/ui/progress";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { PermissionCheckbox } from "./permission-checkbox";
import { userPermissionService } from "@/apis/userPermissionService";
import { permissionService } from "@/apis/permissionService";
import { MODULE_DISPLAY_NAMES } from "@/constants/permissions";
import { toast } from "sonner";
import { cn } from "@/lib/utils";
import {
  Search,
  CheckCircle,
  XCircle,
  ChevronDown,
  Save,
  RefreshCw,
  SearchX,
  UserCog,
  Info,
  RotateCcw,
} from "lucide-react";

export function UserPermissionModal({
  open,
  onOpenChange,
  user,
  userIds,
  role,
  onUpdated,
  isBulk = false,
}) {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [allPermissions, setAllPermissions] = useState({});
  const [selectedPermissions, setSelectedPermissions] = useState(new Set());
  const [initialPermissions, setInitialPermissions] = useState(new Set());
  const [rolePermissions, setRolePermissions] = useState(new Set());
  const [search, setSearch] = useState("");
  const [moduleFilter, setModuleFilter] = useState("all");
  const [expandedModules, setExpandedModules] = useState(new Set());

  const fetchData = useCallback(async () => {
    try {
      setLoading(true);

      // Lấy tất cả permissions
      const permissionsResponse =
        await permissionService.getPermissionsByModule(false);

      if (!permissionsResponse || !permissionsResponse.permissions) {
        throw new Error("Không thể tải danh sách quyền");
      }

      setAllPermissions(permissionsResponse.permissions);

      // Lấy quyền của user (nếu single mode)
      if (!isBulk && user) {
        const userPermsResponse =
          await userPermissionService.getUserPermissions(user.id);

        if (userPermsResponse && userPermsResponse.permissions) {
          const allUserPermissions = new Set(); // TẤT CẢ quyền user có
          const roleOnlyPermissions = new Set(); // Quyền CHỈ từ role (để hiển thị badge)

          Object.values(userPermsResponse.permissions).forEach((perms) => {
            perms.forEach((p) => {
              allUserPermissions.add(p.id); // Thêm tất cả vào selected
              if (p.source === "role" && !p.hasBothSources) {
                roleOnlyPermissions.add(p.id); // Badge "Từ vai trò"
              }
            });
          });

          setSelectedPermissions(allUserPermissions);
          setInitialPermissions(new Set(allUserPermissions));
          setRolePermissions(roleOnlyPermissions); // Chỉ để hiển thị badge
        }
      } else {
        // Bulk mode: start with empty
        setSelectedPermissions(new Set());
        setInitialPermissions(new Set());
        setRolePermissions(new Set());
      }

      const modules = Object.keys(permissionsResponse.permissions);
      setExpandedModules(new Set(modules.slice(0, 3)));
    } catch (error) {
      console.error("Lỗi khi tải dữ liệu:", error);
      toast.error("Không thể tải danh sách quyền");
    } finally {
      setLoading(false);
    }
  }, [isBulk, role?.id, user, user?.id, userIds]);

  useEffect(() => {
    if (open && (user || isBulk)) {
      fetchData();
    }
  }, [open, user, isBulk, fetchData]);

  const handleTogglePermission = (permissionId) => {
    setSelectedPermissions((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(permissionId)) {
        newSet.delete(permissionId);
      } else {
        newSet.add(permissionId);
      }
      return newSet;
    });
  };

  const handleToggleModule = (module) => {
    const modulePermissions = filteredPermissions[module] || [];
    const moduleIds = modulePermissions.map((p) => p.id);
    const allSelected = moduleIds.every((id) => selectedPermissions.has(id));

    setSelectedPermissions((prev) => {
      const newSet = new Set(prev);
      if (allSelected) {
        moduleIds.forEach((id) => newSet.delete(id));
      } else {
        moduleIds.forEach((id) => newSet.add(id));
      }
      return newSet;
    });
  };

  const handleSave = async () => {
    try {
      setSaving(true);
      const permissionIds = Array.from(selectedPermissions);

      if (isBulk) {
        await userPermissionService.bulkUpdateUserPermissions(
          userIds,
          permissionIds,
        );
        toast.success(`Cập nhật quyền cho ${userIds.length} users thành công`);
      } else {
        await userPermissionService.updateUserPermissions(
          user.id,
          permissionIds,
        );
        toast.success("Cập nhật quyền user thành công");
      }

      setInitialPermissions(new Set(selectedPermissions));

      if (onUpdated) {
        onUpdated();
      }

      onOpenChange(false);
    } catch (error) {
      console.error("Lỗi khi cập nhật quyền:", error);
      toast.error(error.response?.data?.message || "Không thể cập nhật quyền");
    } finally {
      setSaving(false);
    }
  };

  const filteredPermissions = useMemo(() => {
    let result = { ...allPermissions };

    if (moduleFilter !== "all") {
      result = { [moduleFilter]: allPermissions[moduleFilter] || [] };
    }

    if (search.trim()) {
      const lowerSearch = search.toLowerCase();
      const filtered = {};

      Object.entries(result).forEach(([module, perms]) => {
        const matched = perms.filter(
          (p) =>
            p.name.toLowerCase().includes(lowerSearch) ||
            p.displayName.toLowerCase().includes(lowerSearch),
        );
        if (matched.length > 0) {
          filtered[module] = matched;
        }
      });

      result = filtered;
    }

    return result;
  }, [allPermissions, moduleFilter, search]);

  const stats = useMemo(() => {
    let totalFiltered = 0;
    let selectedFiltered = 0;

    Object.values(filteredPermissions).forEach((perms) => {
      totalFiltered += perms.length;
      selectedFiltered += perms.filter((p) =>
        selectedPermissions.has(p.id),
      ).length;
    });

    return {
      total: totalFiltered,
      selected: selectedFiltered,
      percentage:
        totalFiltered > 0 ? (selectedFiltered / totalFiltered) * 100 : 0,
    };
  }, [filteredPermissions, selectedPermissions]);

  const hasChanges = useMemo(() => {
    if (selectedPermissions.size !== initialPermissions.size) return true;
    for (const id of selectedPermissions) {
      if (!initialPermissions.has(id)) return true;
    }
    return false;
  }, [selectedPermissions, initialPermissions]);

  const toggleModuleExpand = (module) => {
    setExpandedModules((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(module)) {
        newSet.delete(module);
      } else {
        newSet.add(module);
      }
      return newSet;
    });
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl h-[90vh] flex flex-col p-0 bg-white border-2 border-black rounded-none shadow-hard">
        <DialogHeader className="p-6 border-b-2 border-black">
          <DialogTitle className="text-xl flex items-center gap-3 font-bold uppercase tracking-wider">
            <div className="h-8 w-8 bg-black text-white flex items-center justify-center">
              <UserCog className="h-5 w-5" />
            </div>
            {isBulk
              ? `CHỈNH QUYỀN CHO ${userIds?.length || 0} USERS`
              : `CHỈNH QUYỀN - ${user?.fullName || user?.email}`}
          </DialogTitle>
          <DialogDescription className="text-gray-500 mt-1 font-mono text-xs uppercase">
            {isBulk
              ? "QUYỀN ĐƯỢC THÊM SẼ ÁP DỤNG CHO TẤT CẢ USERS"
              : `VAI TRÒ: ${role?.displayName}. QUYỀN CUSTOM SẼ OVERRIDE QUYỀN TỪ ROLE.`}
          </DialogDescription>
        </DialogHeader>

        {loading ? (
          <div className="space-y-4 p-6">
            <Skeleton className="h-10 w-full border border-black" />
            <Skeleton className="h-10 w-full border border-black" />
            <Skeleton className="h-40 w-full border border-black" />
          </div>
        ) : (
          <>
            <div className="space-y-4 p-6 pb-0">
              {!isBulk && rolePermissions.size > 0 && (
                <Alert className="bg-[#F3E600]/10 border-2 border-[#F3E600] text-black rounded-none">
                  <Info className="h-4 w-4 text-black" />
                  <AlertDescription className="text-xs font-mono uppercase">
                    {rolePermissions.size} QUYỀN CÓ BADGE "ROLE" LÀ QUYỀN MẶC
                    ĐỊNH. BẠN CÓ THỂ BỎ CHỌN HOẶC THÊM QUYỀN KHÁC.
                  </AlertDescription>
                </Alert>
              )}

              <div className="flex flex-col sm:flex-row items-center gap-3">
                <div className="relative flex-1 w-full">
                  <div className="absolute left-0 top-0 h-full w-10 bg-black flex items-center justify-center text-white">
                    <Search className="h-4 w-4" />
                  </div>
                  <Input
                    placeholder="TÌM KIẾM QUYỀN..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="pl-12 h-10 rounded-none border border-black bg-white focus-visible:ring-0 focus-visible:border-black focus:bg-yellow-50 uppercase text-xs font-mono"
                  />
                </div>
                <Select value={moduleFilter} onValueChange={setModuleFilter}>
                  <SelectTrigger className="w-full sm:w-[200px] h-10 rounded-none border border-black bg-white uppercase text-xs font-bold">
                    <SelectValue placeholder="LỌC MODULE" />
                  </SelectTrigger>
                  <SelectContent className="rounded-none border-2 border-black bg-white">
                    <SelectItem
                      value="all"
                      className="uppercase font-mono text-xs"
                    >
                      TẤT CẢ MODULES
                    </SelectItem>
                    {Object.keys(allPermissions).map((module) => (
                      <SelectItem
                        key={module}
                        value={module}
                        className="uppercase font-mono text-xs"
                      >
                        {MODULE_DISPLAY_NAMES[module] || module}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white p-4 border border-black">
                <div className="space-y-2 w-full sm:w-auto">
                  <div className="flex items-center gap-3 text-xs font-bold text-black uppercase tracking-wider">
                    <span className="font-mono">
                      ĐÃ CHỌN: {stats.selected} / {stats.total}
                    </span>
                    <span className="bg-[#F3E600] text-black px-2 py-0.5 font-mono">
                      {Math.round(stats.percentage)}%
                    </span>
                  </div>
                  <div className="w-full sm:w-[200px] h-1 bg-gray-200 border border-gray-300">
                    <div
                      className="h-full bg-[#F3E600] transition-all duration-300"
                      style={{ width: `${stats.percentage}%` }}
                    />
                  </div>
                </div>
                <div className="flex gap-2 w-full sm:w-auto">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => {
                      const allIds = new Set();
                      Object.values(filteredPermissions).forEach((perms) => {
                        perms.forEach((p) => allIds.add(p.id));
                      });
                      setSelectedPermissions(allIds);
                    }}
                    disabled={stats.selected === stats.total}
                    className="flex-1 sm:flex-none rounded-none border border-black hover:bg-black hover:text-white uppercase text-xs font-bold"
                  >
                    <CheckCircle className="h-3 w-3 mr-2" />
                    CHỌN TẤT
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setSelectedPermissions(new Set())}
                    disabled={stats.selected === 0}
                    className="flex-1 sm:flex-none rounded-none border border-black hover:bg-black hover:text-white uppercase text-xs font-bold"
                  >
                    <XCircle className="h-3 w-3 mr-2" />
                    BỎ CHỌN
                  </Button>
                </div>
              </div>
            </div>

            <ScrollArea className="flex-1 px-6 py-2 h-[calc(90vh-450px)]">
              <div className="space-y-3 pb-4">
                {Object.keys(filteredPermissions).length === 0 ? (
                  <div className="text-center py-12 text-gray-500 bg-white border border-black border-dashed">
                    <SearchX className="h-12 w-12 mx-auto mb-2 opacity-30" />
                    <p className="uppercase font-mono text-xs">
                      KHÔNG TÌM THẤY QUYỀN
                    </p>
                  </div>
                ) : (
                  Object.entries(filteredPermissions).map(
                    ([module, permissions]) => {
                      const moduleSelected = permissions.filter((p) =>
                        selectedPermissions.has(p.id),
                      ).length;
                      const moduleTotal = permissions.length;
                      const isExpanded = expandedModules.has(module);

                      return (
                        <div
                          key={module}
                          className="border border-black overflow-hidden transition-all hover:shadow-hard"
                        >
                          <div
                            className="flex items-center justify-between p-4 bg-white cursor-pointer select-none hover:bg-gray-50 border-l-4 border-l-transparent hover:border-l-[#F3E600] transition-all"
                            onClick={() => toggleModuleExpand(module)}
                          >
                            <div className="flex items-center gap-3">
                              <div onClick={(e) => e.stopPropagation()}>
                                <Checkbox
                                  checked={
                                    moduleSelected === moduleTotal &&
                                    moduleTotal > 0
                                      ? true
                                      : moduleSelected > 0
                                        ? "indeterminate"
                                        : false
                                  }
                                  onCheckedChange={() =>
                                    handleToggleModule(module)
                                  }
                                  className="data-[state=checked]:bg-[#F3E600] data-[state=checked]:border-black data-[state=checked]:text-black rounded-none border-2"
                                />
                              </div>
                              <div className="flex items-center gap-3">
                                <div className="h-8 w-1 bg-black"></div>
                                <div>
                                  <Label className="font-bold text-black text-sm cursor-pointer uppercase tracking-tight">
                                    {MODULE_DISPLAY_NAMES[module] || module}
                                  </Label>
                                  <p className="text-xs text-gray-500 font-mono mt-0.5 uppercase">
                                    {moduleSelected}/{moduleTotal} QUYỀN
                                  </p>
                                </div>
                              </div>
                            </div>
                            <div className="flex items-center gap-3">
                              <Badge
                                variant="secondary"
                                className="bg-black text-white rounded-none px-2.5 py-1 font-mono text-xs uppercase"
                              >
                                {module}
                              </Badge>
                              <ChevronDown
                                className={cn(
                                  "h-4 w-4 text-black transition-transform duration-200",
                                  isExpanded ? "rotate-180" : "",
                                )}
                              />
                            </div>
                          </div>

                          {isExpanded && (
                            <div className="p-4 space-y-2 bg-gray-50 border-t-2 border-black">
                              {permissions.map((permission) => {
                                const isInherited = rolePermissions.has(
                                  permission.id,
                                );
                                const isCustomSelected =
                                  selectedPermissions.has(permission.id);
                                const isChecked =
                                  isInherited || isCustomSelected;

                                return (
                                  <PermissionCheckbox
                                    key={permission.id}
                                    permission={permission}
                                    checked={isChecked}
                                    onCheckedChange={() =>
                                      handleTogglePermission(permission.id)
                                    }
                                    isInherited={isInherited}
                                    showSource={!isBulk}
                                  />
                                );
                              })}
                            </div>
                          )}
                        </div>
                      );
                    },
                  )
                )}
              </div>
            </ScrollArea>

            <DialogFooter className="flex items-center justify-between p-6 border-t-2 border-black">
              <div>
                {!isBulk && rolePermissions.size > 0 && (
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() =>
                      setSelectedPermissions(new Set(rolePermissions))
                    }
                    disabled={saving}
                    className="text-black hover:bg-gray-100 border border-black rounded-none uppercase text-xs font-bold"
                  >
                    <RotateCcw className="h-3 w-3 mr-2" />
                    ĐẶT LẠI MẶC ĐỊNH
                  </Button>
                )}
              </div>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  onClick={() => onOpenChange(false)}
                  className="rounded-none border border-black hover:bg-gray-100 uppercase text-xs font-bold"
                >
                  HỦY
                </Button>
                <Button
                  onClick={handleSave}
                  disabled={!hasChanges || saving}
                  className="rounded-none bg-black hover:bg-[#F3E600] hover:text-black text-white border border-black shadow-hard uppercase text-xs font-bold"
                >
                  {saving ? (
                    <span className="flex items-center gap-2">
                      <RefreshCw className="h-3 w-3 animate-spin" />
                      ĐANG LƯU...
                    </span>
                  ) : (
                    <span className="flex items-center gap-2">
                      <Save className="h-3 w-3" />
                      LƯU THAY ĐỔI
                    </span>
                  )}
                </Button>
              </div>
            </DialogFooter>
          </>
        )}
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Label } from "@/components/ui/Label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/Dialog";
import { Checkbox } from "@/components/ui/checkbox";
import useTagStore from "@/stores/tagStore";
import { useToast } from "@/hooks/use-toast";
import { TAG_TYPES, TAG_COLOR_PRESETS } from "@/constants/tagConstants";

/**
 * TAG FORM DIALOG
 * Form tạo/sửa tag
 */

export default function TagFormDialog({ open, onClose, tag }) {
  const { createTag, updateTag, fetchTags } = useTagStore();
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    name: "",
    slug: "",
    tagType: "general",
    icon: "",
    color: "#6B7280",
    isActive: true,
  });

  useEffect(() => {
    if (tag) {
      setFormData({
        name: tag.name || "",
        slug: tag.slug || "",
        tagType: tag.tagType || "general",
        icon: tag.icon || "",
        color: tag.color || "#6B7280",
        isActive: tag.isActive !== undefined ? tag.isActive : true,
      });
    } else {
      setFormData({
        name: "",
        slug: "",
        tagType: "general",
        icon: "",
        color: "#6B7280",
        isActive: true,
      });
    }
  }, [tag, open]);

  const handleChange = (field, value) => {
    setFormData((prev) => ({ ...prev, [field]: value }));

    // Auto-generate slug from name
    if (field === "name" && !tag) {
      const slug = value
        .toLowerCase()
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .replace(/đ/g, "d")
        .replace(/[^a-z0-9\s-]/g, "")
        .trim()
        .replace(/\s+/g, "-");
      setFormData((prev) => ({ ...prev, slug }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      if (tag) {
        await updateTag(tag.id, formData);
        toast({
          title: "Success",
          description: "Tag updated successfully",
        });
      } else {
        await createTag(formData);
        toast({
          title: "Success",
          description: "Tag created successfully",
        });
      }
      await fetchTags();
      onClose();
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Error",
        description: error.response?.data?.message || error.message,
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-xl">
        <DialogHeader>
          <DialogTitle>{tag ? "Edit Tag" : "Add Tag"}</DialogTitle>
          <DialogDescription>
            {tag ? "Update tag information" : "Create a new tag"}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Name & Slug */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="name">
                Name <span className="text-destructive">*</span>
              </Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => handleChange("name", e.target.value)}
                placeholder="e.g. Giá rẻ"
                required
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="slug">
                Slug <span className="text-destructive">*</span>
              </Label>
              <Input
                id="slug"
                value={formData.slug}
                onChange={(e) => handleChange("slug", e.target.value)}
                placeholder="e.g. gia-re"
                required
              />
            </div>
          </div>

          {/* Tag Type */}
          <div className="space-y-2">
            <Label htmlFor="tagType">
              Tag Type <span className="text-destructive">*</span>
            </Label>
            <Select
              value={formData.tagType}
              onValueChange={(val) => handleChange("tagType", val)}
            >
              <SelectTrigger>
                <SelectValue placeholder="Select tag type" />
              </SelectTrigger>
              <SelectContent>
                {Object.entries(TAG_TYPES).map(([value, label]) => (
                  <SelectItem key={value} value={value}>
                    {label}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Color */}
          <div className="space-y-2">
            <Label htmlFor="color">Color</Label>
            <div className="flex gap-2">
              <Input
                id="color"
                type="color"
                value={formData.color}
                onChange={(e) => handleChange("color", e.target.value)}
                className="w-20 h-10"
              />
              <div className="flex flex-wrap gap-1 flex-1">
                {TAG_COLOR_PRESETS.map((color) => (
                  <button
                    key={color}
                    type="button"
                    className="w-8 h-8 rounded border-2 hover:scale-110 transition-transform"
                    style={{
                      backgroundColor: color,
                      borderColor:
                        formData.color === color ? "#000" : "transparent",
                    }}
                    onClick={() => handleChange("color", color)}
                  />
                ))}
              </div>
            </div>
          </div>

          {/* Icon (Optional) */}
          <div className="space-y-2">
            <Label htmlFor="icon">Icon (Optional)</Label>
            <Input
              id="icon"
              value={formData.icon}
              onChange={(e) => handleChange("icon", e.target.value)}
              placeholder="Lucide icon name"
            />
          </div>

          {/* Active Status */}
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-2">
              <Checkbox
                id="isActive"
                checked={formData.isActive}
                onCheckedChange={(checked) => handleChange("isActive", checked)}
              />
              <div className="space-y-0.5">
                <Label htmlFor="isActive" className="cursor-pointer">
                  Active Status
                </Label>
                <p className="text-xs text-muted-foreground">
                  Inactive tags won't be shown in filters
                </p>
              </div>
            </div>
          </div>

          <DialogFooter>
            <Button
              type="button"
              variant="outline"
              onClick={onClose}
              disabled={loading}
            >
              Cancel
            </Button>
            <Button type="submit" disabled={loading}>
              {loading ? "Saving..." : tag ? "Update" : "Create"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva } from "class-variance-authority";
import Loader2 from "lucide-react/dist/esm/icons/loader-2";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive:
          "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline:
          "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-md px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

const Button = React.forwardRef(
  (
    {
      className,
      variant,
      size,
      asChild = false,
      loading = false,
      children,
      disabled,
      ...props
    },
    ref,
  ) => {
    const Comp = asChild ? Slot : "button";

    // Khi asChild=true, Slot chỉ chấp nhận 1 child, không thể thêm Loader
    if (asChild) {
      return (
        <Comp
          className={cn(buttonVariants({ variant, size, className }))}
          ref={ref}
          {...props}
        >
          {children}
        </Comp>
      );
    }

    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        disabled={disabled || loading}
        {...props}
      >
        {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
        {children}
      </Comp>
    );
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };

