      ["get", "point_count"],
      "#334155", // 0–9
      10,
      "#1d4ed8", // 10–29
      30,
      "#7c3aed", // 30+
    ],
    "circle-radius": ["step", ["get", "point_count"], 20, 10, 26, 30, 32],
    "circle-stroke-width": 3,
    "circle-stroke-color": "#ffffff",
    "circle-opacity": 0.93,
  },
