};

// ─── Main Component ───────────────────────────────────────────────────────────

const CLICK_LAYERS = [
  "place-clusters",
  "place-cluster-count",
  "place-unclustered",
  "place-featured",
];

const PlaceMarkers = () => {
  const { filteredPlaces, places, flyTo, mapRef, routingMode, routing } =
    useMapContext();
  const [activePlace, setActivePlace] = useState(null);
  // routingPickerState: { place, x, y } where x/y are fixed screen coords
  const [routingPickerState, setRoutingPickerState] = useState(null);
  const [zoom, setZoom] = useState(null);
  const activeFeatIdRef = useRef(null);

  // Stable refs for routing (prevents stale closure in map.on handler)
  const routingModeRef = useRef(routingMode);
  useEffect(() => {
    routingModeRef.current = routingMode;
  }, [routingMode]);
  const routingRef = useRef(routing);
  useEffect(() => {
    routingRef.current = routing;
  }, [routing]);
  const setRoutingPickerRef = useRef(setRoutingPickerState);

  // ── Zoom tracking ─────────────────────────────────────────────────────────
  useEffect(() => {
    const map = mapRef.current?.getMap?.();
    if (!map) return;
    const onZoom = () => setZoom(map.getZoom());
    const syncZoom = () => setZoom(map.getZoom());
    if (map.loaded()) {
      requestAnimationFrame(syncZoom);
    } else {
      map.once("load", syncZoom);
    }
    map.on("zoom", onZoom);
    return () => map.off("zoom", onZoom);
  }, [mapRef]);

  const isCardMode = zoom != null && zoom >= CARD_ZOOM;
  const isCardModeRef = useRef(isCardMode);
  useEffect(() => {
    isCardModeRef.current = isCardMode;
      const id = requestAnimationFrame(() => setVisibleBounds(null));
      return () => cancelAnimationFrame(id);
    }
    const map = mapRef.current?.getMap?.();
    if (!map) return;
    const update = () => setVisibleBounds(map.getBounds());
    const initId = requestAnimationFrame(update);
    map.on("moveend", update);
    map.on("zoomend", update);
    return () => {
      cancelAnimationFrame(initId);
      map.off("moveend", update);
      map.off("zoomend", update);
    };
  }, [mapRef, isCardMode]);

  const visiblePlaces = useMemo(() => {
    if (!isCardMode || !visibleBounds) return [];
    return filteredPlaces.filter((p) => {
      if (!p.latitude || !p.longitude) return false;
      const lng = Number(p.longitude);
      const lat = Number(p.latitude);
      return (
        lng >= visibleBounds.getWest() &&
        lng <= visibleBounds.getEast() &&
        lat >= visibleBounds.getSouth() &&
        lat <= visibleBounds.getNorth()
      );
    });
  }, [isCardMode, visibleBounds, filteredPlaces]);

  const activePlaceRef = useRef(activePlace);
  useEffect(() => {
    activePlaceRef.current = activePlace;
  }, [activePlace]);

  const routingPickerStateRef = useRef(routingPickerState);
  useEffect(() => {
    routingPickerStateRef.current = routingPickerState;
  }, [routingPickerState]);

  // Keep popup position synced when map moves (for active place)
  useEffect(() => {
    const map = mapRef.current?.getMap?.();
    if (!map) return;

    const onMove = () => {
      if (!activePlaceRef.current) return;
      const p = activePlaceRef.current;
      const point = map.project([Number(p.longitude), Number(p.latitude)]);
      const popupWidth = 340;
      const popupHeight = 420;
      const margin = 16;
      const mapW = map.getContainer().clientWidth;
      const mapH = map.getContainer().clientHeight;

      let x = point.x + 20;
      let y = point.y - popupHeight / 2;

      if (x + popupWidth > mapW - margin) x = point.x - popupWidth - 20;
      if (x < margin) x = margin;
      if (y < margin) y = margin;
      if (y + popupHeight > mapH - margin) y = mapH - popupHeight - margin;

      setPopupPos({ x, y });
    };

    map.on("move", onMove);
    return () => map.off("move", onMove);
  }, [mapRef]);

  // Close popup/picker when clicking map background
  useEffect(() => {
    const map = mapRef.current?.getMap?.();
    if (!map) return;

    const onMapClick = () => {
      if (routingPickerStateRef.current) {
        setRoutingPickerState(null);
        return;
      }
      if (activePlaceRef.current) {
        const m = mapRef.current?.getMap?.();
        clearActiveState(m, activeFeatIdRef.current);
        activeFeatIdRef.current = null;
        setActivePlace(null);
      }
    };

    map.on("click", onMapClick);
    return () => map.off("click", onMapClick);
  }, [mapRef, clearActiveState]);

  // Also dismiss routing picker when routing mode turns off
  useEffect(() => {
    if (!routingMode) {
      const id = requestAnimationFrame(() => setRoutingPickerState(null));
      return () => cancelAnimationFrame(id);
    }
  }, [routingMode]);

  return (
    <>
      <Source
        id="places-source"
        type="geojson"
        data={geojson}
        cluster
        clusterMaxZoom={13}
        clusterRadius={50}
        promoteId="id"
      >
        <Layer {...CLUSTER_CIRCLE_LAYER} />
        <Layer {...CLUSTER_COUNT_LAYER} />
        <Layer {...UNCLUSTERED_ACTIVE_LAYER} paint={activePaint} />
        <Layer {...UNCLUSTERED_CIRCLE_LAYER} paint={unclusteredPaint} />
        <Layer {...FEATURED_DOT_LAYER} paint={featuredPaint} />
      </Source>

      {/* DOM image-pin markers – zoomed-in card mode */}
      {isCardMode &&
        visiblePlaces.map((p) => (
          <Marker
            key={p.id}
            latitude={Number(p.latitude)}
            longitude={Number(p.longitude)}
            anchor="bottom"
            onClick={(e) => handlePinClick(p, e.originalEvent || e)}
          >
            <div className="relative -translate-y-1 cursor-pointer">
              <div
                className={cn(
                  "w-12 h-12 rounded-full border-2 shadow-lg overflow-hidden bg-white",
                  p.isFeatured ? "border-amber-400" : "border-primary",
                )}
              >
                {p.coverImage ? (
                  <img
                    src={p.coverImage}
                    alt={p.name}
                    className="w-full h-full object-cover"
                    loading="lazy"
                  />
                ) : (
                  <div className="w-full h-full bg-gray-100 flex items-center justify-center">
                    <MapPin className="w-4 h-4 text-gray-500" />
                  </div>
                )}
              </div>
              <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-3 h-3 bg-white border-r-2 border-b-2 border-primary rotate-45" />
            </div>
          </Marker>
        ))}

      {/* Floating popup panel */}
      {activePlace && popupPos && !routingMode && !isCardMode && (
        <PlacePopupCard
          place={activePlace}
          position={popupPos}
          onClose={handlePopupClose}
          onDetail={onOpenDetail}
          onStart={() => onStartRoute(activePlace)}
        />
      )}

      {/* Compact routing picker */}
      {routingPickerState && (
        <RoutingPicker
          place={routingPickerState.place}
          position={{ x: routingPickerState.x, y: routingPickerState.y }}
          onSelect={(mode) => {
            const p = routingPickerState.place;
            setRoutingPickerState(null);
            if (mode === "start") {
              setRouteStart({
                lat: Number(p.latitude),
                lng: Number(p.longitude),
                name: p.name,
              });
              if (routeEnd) setRouteProfile("driving");
            } else {
              setRouteEnd({
                lat: Number(p.latitude),
                lng: Number(p.longitude),
                name: p.name,
              });
            }
          }}
          onClose={() => setRoutingPickerState(null)}
        />
      )}
    </>
  );
        setRoutingPickerRef.current(null);
        setActivePlaceRef.current(placeData);
      }
      flyToRef.current(
        { lat: Number(placeData.latitude), lng: Number(placeData.longitude) },
        15,
      );
    },
    [mapRef, clearActiveState],
  );

  /** Attach click + cursor listeners once when the map is loaded; stable via refs */
  useEffect(() => {
    const map = mapRef.current?.getMap?.();
    if (!map) return;

    const showPointer = () => {
      map.getCanvas().style.cursor = "pointer";
    };
    const resetPointer = () => {
      map.getCanvas().style.cursor = "";
    };

    const attach = () => {
      map.on("click", handleClick);
      CLICK_LAYERS.forEach((layer) => {
        map.on("mouseenter", layer, showPointer);
        map.on("mouseleave", layer, resetPointer);
      });
    };
    const detach = () => {
      map.off("click", handleClick);
      CLICK_LAYERS.forEach((layer) => {
        map.off("mouseenter", layer, showPointer);
        map.off("mouseleave", layer, resetPointer);
      });
    };

    if (map.loaded()) {
      attach();
    } else {
      map.once("load", attach);
    }
    return detach;
  }, [mapRef, handleClick]);

  const handlePopupClose = useCallback(() => {
    const map = mapRef.current?.getMap?.();
    clearActiveState(map, activeFeatIdRef.current);
    activeFeatIdRef.current = null;
    setActivePlace(null);
    setRoutingPickerState(null);
  }, [mapRef, clearActiveState]);

  /** Click on a DOM Marker pin */
  const handlePinClick = useCallback(
    (place, e) => {
      e?.stopPropagation?.();
      const map = mapRef.current?.getMap?.();

      clearActiveState(map, activeFeatIdRef.current);
      activeFeatIdRef.current = place.id;
      try {
        map?.setFeatureState(
          { source: "places-source", id: place.id },
          { active: true },
        );
      } catch {
        // Feature may disappear between query and state update.
      }

      if (routingModeRef.current) {
        setActivePlace(null);
        const clientX = e?.clientX ?? 0;
        const clientY = e?.clientY ?? 0;
        setRoutingPickerState({ place, x: clientX, y: clientY });
      } else {
        setRoutingPickerState(null);
        setActivePlace(place);
      }
      flyToRef.current(
        { lat: Number(place.latitude), lng: Number(place.longitude) },
        Math.max(zoom || 15, 15),
      );
    },
    [mapRef, clearActiveState, zoom],
  );

  // Close routing picker when clicking map background
  useEffect(() => {
    if (!routingPickerState) return;
    const map = mapRef.current?.getMap?.();
    if (!map) return;
    const onMapClick = () => setRoutingPickerState(null);
    map.on("click", onMapClick);
    return () => map.off("click", onMapClick);
  }, [mapRef, routingPickerState]);

  // Also dismiss routing picker when routing mode turns off
  useEffect(() => {
    if (!routingMode) setRoutingPickerState(null);
  }, [routingMode]);

  return (
    <>
      <Source
        id="places-source"
        type="geojson"
        data={geojson}
        cluster
        clusterMaxZoom={13}
        clusterRadius={50}
        promoteId="id"
      >
        <Layer {...CLUSTER_CIRCLE_LAYER} />
        <Layer {...CLUSTER_COUNT_LAYER} />
        <Layer {...UNCLUSTERED_ACTIVE_LAYER} paint={activePaint} />
        <Layer {...UNCLUSTERED_CIRCLE_LAYER} paint={unclusteredPaint} />
        <Layer {...FEATURED_DOT_LAYER} paint={featuredPaint} />
      </Source>

      {/* DOM image-pin markers – zoomed-in card mode */}
      {isCardMode &&
        visiblePlaces.map((p) => (
          <Marker
            key={p.id}
            latitude={Number(p.latitude)}
            longitude={Number(p.longitude)}
            anchor="bottom"
            style={{ zIndex: activePlace?.id === p.id ? 50 : 10 }}
          >
            <PlacePin
              place={p}
              isActive={activePlace?.id === p.id}
              onClick={(e) => handlePinClick(p, e)}
            />
          </Marker>
        ))}

      {activePlace && (
        <Popup
          anchor="top"
          latitude={Number(activePlace.latitude)}
          longitude={Number(activePlace.longitude)}
          onClose={handlePopupClose}
          closeOnClick={false}
          closeButton={false}
          offset={16}
          maxWidth="320px"
        >
          <PlacePopup place={activePlace} onClose={handlePopupClose} />
        </Popup>
      )}

      {/* Routing picker rendered as portal outside MapLibre DOM */}
      {routingPickerState && (
        <RoutingPicker
          place={routingPickerState.place}
          screenX={routingPickerState.x}
          screenY={routingPickerState.y}
          onClose={() => setRoutingPickerState(null)}
          onSetOrigin={() => {
            const p = routingPickerState.place;
            routingRef.current?.setOrigin({
              lat: Number(p.latitude),
              lng: Number(p.longitude),
              name: p.name,
              address: p.address,
            });
            setRoutingPickerState(null);
            clearActiveState(
              mapRef.current?.getMap?.(),
              activeFeatIdRef.current,
            );
            activeFeatIdRef.current = null;
          }}
          onSetDestination={() => {
            const p = routingPickerState.place;
            routingRef.current?.setDestination({
              lat: Number(p.latitude),
              lng: Number(p.longitude),
              name: p.name,
              address: p.address,
            });
            setRoutingPickerState(null);
            clearActiveState(
              mapRef.current?.getMap?.(),
              activeFeatIdRef.current,
            );
            activeFeatIdRef.current = null;
          }}
        />
      )}
    </>
  );
};

export default PlaceMarkers;

import {
  createContext,
  useContext,
  useState,
  useCallback,
  useMemo,
  useRef,
} from "react";
import {
  MAP_CONFIGS,
  MAP_STYLES,
  DEFAULT_MAP_STYLE,
} from "../config/mapConfig";
import { useRouting } from "../hooks/useRouting";

const MapContext = createContext(null);
const FLY_DURATION_MS = 1000;

export const MapProvider = ({ children }) => {
  const mapRef = useRef(null);
  const [viewState, setViewState] = useState(MAP_CONFIGS.INITIAL_VIEW);
  const [basemap, setBasemap] = useState(DEFAULT_MAP_STYLE);
  const [selectedDistrict, setSelectedDistrict] = useState(null);
  const [selectedWard, setSelectedWard] = useState(null);
  const [hoveredFeature, setHoveredFeature] = useState(null);
  const [places, setPlaces] = useState([]);
  const [filteredPlaces, setFilteredPlaces] = useState([]);

  /**
   * Stable ref for the "view place detail" callback.
   * Page consumers call setOnSelectPlace(fn) on mount to register their handler.
   */
  const onSelectPlaceCbRef = useRef(null);

  const flyTo = useCallback((coords, zoom = 13) => {
    const map = mapRef.current?.getMap?.();
    if (map) {
      map.flyTo({
        center: [coords.lng, coords.lat],
        zoom,
        duration: FLY_DURATION_MS,
      });
    }
  }, []);

  const selectArea = useCallback((feature, type = "district") => {
    if (type === "district") {
      setSelectedDistrict(feature);
      setSelectedWard(null);
    } else {
      setSelectedWard(feature);
    }
  }, []);

  const resetSelection = useCallback(() => {
    setSelectedDistrict(null);
    setSelectedWard(null);
    setHoveredFeature(null);
  }, []);

  const setOnSelectPlace = useCallback((fn) => {
    onSelectPlaceCbRef.current = fn ?? null;
  }, []);

  const selectPlace = useCallback((place) => {
    onSelectPlaceCbRef.current?.(place);
  }, []);

  // ─── Phase 1: Routing ─────────────────────────────────────────────────────
  const [routingMode, setRoutingMode] = useState(false); // whether routing panel is visible
  const routing = useRouting();

  const value = useMemo(
    () => ({
      mapRef,
      viewState,
      setViewState,
      basemap,
      setBasemap,
      MAP_STYLES,
      selectedDistrict,
      selectedWard,
      hoveredFeature,
      setHoveredFeature,
      selectArea,
      resetSelection,
      flyTo,
      places,
      setPlaces,
      filteredPlaces,
      setFilteredPlaces,
      selectPlace,
      setOnSelectPlace,
      // Routing
      routingMode,
      setRoutingMode,
      routing,
    }),
    [
      viewState,
      basemap,
      selectedDistrict,
      selectedWard,
      hoveredFeature,
      selectArea,
      resetSelection,
      flyTo,
      places,
      filteredPlaces,
      selectPlace,
      setOnSelectPlace,
      routingMode,
      routing,
    ],
  );

  return <MapContext.Provider value={value}>{children}</MapContext.Provider>;
};

export const useMapContext = () => {
  const context = useContext(MapContext);
  if (!context) {
    throw new Error("useMapContext must be used within a MapProvider");
  }
  return context;
};

import { useState, useEffect, useCallback } from "react";
import FileText from "lucide-react/dist/esm/icons/file-text";
import RefreshCw from "lucide-react/dist/esm/icons/refresh-cw";
import Eye from "lucide-react/dist/esm/icons/eye";
import Filter from "lucide-react/dist/esm/icons/filter";
import CheckCircle from "lucide-react/dist/esm/icons/check-circle";
import Edit from "lucide-react/dist/esm/icons/edit";
import Trash2 from "lucide-react/dist/esm/icons/trash-2";
import AlertCircle from "lucide-react/dist/esm/icons/alert-circle";
import toast from "react-hot-toast";
import {
  Card,
  CardHeader,
  CardTitle,
  CardContent,
  Button,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui";
import auditLogService from "@/apis/auditLogService";
import { formatDateTime } from "@/utils/dateUtils";
import TimStatsCard from "@/components/admin/TimStatsCard";

const AuditLogsPage = () => {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedLog, setSelectedLog] = useState(null);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [stats, setStats] = useState({
    total: 0,
    create: 0,
    update: 0,
    delete: 0,
  });

  // Filters
  const [actionFilter, setActionFilter] = useState("all");
  const [tableFilter, setTableFilter] = useState("all");
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const itemsPerPage = 10;

  // Fetch logs
  const fetchLogs = useCallback(async () => {
    try {
      setLoading(true);
      const params = {
        page: currentPage,
        limit: itemsPerPage,
        action: actionFilter === "all" ? undefined : actionFilter,
        tableName: tableFilter === "all" ? undefined : tableFilter,
      };
      const response = await auditLogService.getAll(params);
      if (response.success) {
        setLogs(response.data || []);
        setTotalPages(response.pagination?.totalPages || 1);

        // Calculate stats from current logs
        const allLogs = response.data || [];
        setStats({
          total: response.pagination?.total || allLogs.length,
          create: allLogs.filter((l) => l.action === "CREATE").length,
          update: allLogs.filter(
            (l) =>
              l.action === "UPDATE" ||
              l.action === "UPDATE_ROLE" ||
              l.action === "UPDATE_PERMISSIONS",
          ).length,
          delete: allLogs.filter((l) => l.action === "DELETE").length,
        });
      }
    } catch (error) {
      toast.error("Lỗi khi tải audit logs");
      console.error(error);
    } finally {
      setLoading(false);
    }
  }, [actionFilter, currentPage, tableFilter]);

  useEffect(() => {
    fetchLogs();
  }, [fetchLogs]);

  // View detail
  const handleViewDetail = async (log) => {
    try {
      const response = await auditLogService.getById(log.id);
      if (response.success) {
        setSelectedLog(response.data);
        setShowDetailModal(true);
      }
    } catch (error) {
      toast.error("Lỗi khi tải chi tiết log");
      console.error(error);
    }
  };

  // Get action color
  const getActionColor = (action) => {
    const colors = {
      CREATE: "bg-green-100 text-green-700",
      UPDATE: "bg-blue-100 text-blue-700",
      DELETE: "bg-red-100 text-red-700",
      UPDATE_ROLE: "bg-orange-100 text-orange-700",
      UPDATE_PERMISSIONS: "bg-purple-100 text-purple-700",
      ASSIGN_TAGS: "bg-cyan-100 text-cyan-700",
    };
    return colors[action] || "bg-gray-100 text-gray-700";
  };

  return (
    <div className="min-h-screen p-8 bg-background relative">
      {/* Enhanced grid background with dots */}
      <div className="absolute inset-0 bg-grid-dots opacity-60 pointer-events-none"></div>
      <div className="absolute inset-0 bg-grid-lines opacity-20 pointer-events-none"></div>

      <div className="relative z-10 space-y-6 max-w-[1600px] mx-auto">
        {/* Header */}
        <div className="flex items-end justify-between border-b-2 border-black pb-6">
          <div className="flex items-center gap-6">
            <div className="accent-bar h-16"></div>
            <div>
              <h1 className="tim-title">AUDIT LOGS</h1>
              <div className="flex items-center gap-4 mt-2">
                <span className="tim-system bg-black text-white px-2 py-1">
                  SYSTEM // AUDIT TRACKING
                </span>
                <p className="tim-meta">LỊCH SỚ HOẠT ĐỘNG QUẢN TRỊ VIÊN</p>
              </div>
            </div>
          </div>
          <Button
            onClick={() => fetchLogs()}
            disabled={loading}
            variant="outline"
            className="h-12 w-12 rounded-none border border-black hover:bg-black hover:text-white"
          >
            <RefreshCw className={`h-4 w-4 ${loading ? "animate-spin" : ""}`} />
          </Button>
        </div>

        {/* Thống kê nhanh (theo trang hiện tại) */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <TimStatsCard
            title="TỔNG GHI NHẬN"
            value={stats.total}
            icon={FileText}
            serial="AUD-001"
          />
          <TimStatsCard
            title="TẠO MỚI"
            value={stats.create}
            icon={CheckCircle}
            serial="AUD-002"
            textColor="text-emerald-600"
          />
          <TimStatsCard
            title="CẬP NHẬT"
            value={stats.update}
            icon={Edit}
            serial="AUD-003"
            textColor="text-blue-600"
          />
          <TimStatsCard
            title="XÓA"
            value={stats.delete}
            icon={Trash2}
            serial="AUD-004"
            color="bg-yellow-50"
            textColor="text-red-600"
          />
        </div>

        {/* Filter Bar */}
        <div className="bg-white border border-black p-4 shadow-sm">
          <div className="flex items-center justify-between flex-wrap gap-4">
            <span className="tim-meta">BỘ LỌC DỮ LIỆU</span>
            <div className="flex gap-2">
              <select
                value={actionFilter}
                onChange={(e) => {
                  setActionFilter(e.target.value);
                  setCurrentPage(1);
                }}
                className="h-10 px-4 border border-black rounded-none bg-white tim-body uppercase focus:outline-none focus:bg-yellow-50"
              >
                <option value="all">TẤT CẢ HÀNH ĐỘNG</option>
                {auditLogService.getActionTypes().map((action) => (
                  <option key={action} value={action}>
                    {action}
                  </option>
                ))}
              </select>
              <select
                value={tableFilter}
                onChange={(e) => {
                  setTableFilter(e.target.value);
                  setCurrentPage(1);
                }}
                className="h-10 px-4 border border-black rounded-none bg-white tim-body uppercase focus:outline-none focus:bg-yellow-50"
              >
                <option value="all">TẤT CẢ BẢNG</option>
                {auditLogService.getTableNames().map((table) => (
                  <option key={table} value={table}>
                    {table}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* Data Table */}
        <div className="bg-white border border-black shadow-sm overflow-hidden">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20 bg-gray-50">
              <div className="w-8 h-8 border-2 border-black border-t-transparent rounded-full animate-spin mb-2"></div>
              <span className="font-mono text-xs uppercase text-gray-500">
                LOADING DATA...
              </span>
            </div>
          ) : logs.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20">
              <FileText className="h-12 w-12 text-gray-300 mb-4" />
              <div className="font-bold uppercase text-gray-400">
                KHÔNG TÌM THẤY DỮ LIỆU
              </div>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-black text-white tim-table-header">
                    <th className="p-4 border-r border-black/20 w-[60px]">
                      ID
                    </th>
                    <th className="p-4 border-r border-black/20">USER</th>
                    <th className="p-4 border-r border-black/20">HÀNH ĐỘNG</th>
                    <th className="p-4 border-r border-black/20">BẢNG</th>
                    <th className="p-4 border-r border-black/20">RECORD ID</th>
                    <th className="p-4 border-r border-black/20">MÔ TẢ</th>
                    <th className="p-4 border-r border-black/20">THỜI GIAN</th>
                    <th className="p-4 text-center">CHI TIẾT</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-black/5">
                  {logs.map((log) => (
                    <tr
                      key={log.id}
                      className="hover:bg-yellow-50 group transition-colors"
                    >
                      <td className="p-4 font-mono text-sm text-gray-400 border-r border-black/5">
                        #{log.id}
                      </td>
                      <td className="p-4 border-r border-black/5">
                        <div>
                          <div className="font-bold uppercase text-sm">
                            {log.user?.profile?.fullName || "N/A"}
                          </div>
                          <div className="text-gray-500 text-xs font-mono">
                            {log.user?.email || "N/A"}
                          </div>
                        </div>
                      </td>
                      <td className="p-4 border-r border-black/5">
                        <span
                          className={`px-2.5 py-1 rounded-none border border-black text-[10px] font-bold uppercase font-mono ${getActionColor(log.action)}`}
                        >
                          {log.action}
                        </span>
                      </td>
                      <td className="p-4 border-r border-black/5">
                        <span className="font-mono text-sm font-medium">
                          {log.tableName}
                        </span>
                      </td>
                      <td className="p-4 border-r border-black/5">
                        <span className="font-mono text-sm text-gray-600">
                          {log.recordId}
                        </span>
                      </td>
                      <td className="p-4 border-r border-black/5">
                        <span className="text-sm text-gray-600">
                          {log.description || "—"}
                        </span>
                      </td>
                      <td className="p-4 border-r border-black/5">
                        <span className="font-mono text-sm text-gray-500">
                          {formatDateTime(log.createdAt)}
                        </span>
                      </td>
                      <td className="p-4 text-center">
                        <Button
                          size="sm"
                          variant="ghost"
                          onClick={() => handleViewDetail(log)}
                          className="rounded-none border border-transparent hover:border-black hover:bg-white h-8"
                        >
                          <Eye className="w-4 h-4" />
                        </Button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Pagination */}
          {totalPages > 1 && (
            <div className="flex items-center justify-between p-4 border-t border-black bg-gray-50 font-mono text-xs uppercase">
              <div>HIỂN THỊ {logs.length} KẾT QUẢ</div>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                  disabled={currentPage === 1}
                  className="rounded-none border-black h-8 hover:bg-black hover:text-white"
                >
                  TRƯỚC
                </Button>
                <span className="flex items-center px-4 font-bold">
                  {currentPage}
                </span>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() =>
                    setCurrentPage((p) => Math.min(totalPages, p + 1))
                  }
                  disabled={currentPage === totalPages}
                  className="rounded-none border-black h-8 hover:bg-black hover:text-white"
                >
                  SAU
                </Button>
              </div>
            </div>
          )}
        </div>

        {/* Detail Modal - T.I.M Style */}
        <Dialog open={showDetailModal} onOpenChange={setShowDetailModal}>
          <DialogContent className="max-w-4xl max-h-[85vh] overflow-y-auto rounded-none border-2 border-black">
            <DialogHeader className="border-b-2 border-black pb-4">
              <div className="flex items-center gap-4">
                <div className="accent-bar h-12"></div>
                <div>
                  <DialogTitle className="tim-title text-2xl">
                    LOG DETAIL
                  </DialogTitle>
                  <div className="tim-meta mt-1">
                    AUDIT LOG #{selectedLog?.id}
                  </div>
                </div>
              </div>
            </DialogHeader>

            {selectedLog && (
              <div className="space-y-6 pt-4">
                {/* Main Info Grid */}
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-gray-50 border border-black p-4">
                    <label className="tim-meta block mb-2">HÀNH ĐỘNG</label>
                    <span
                      className={`px-3 py-1.5 rounded-none border border-black text-xs font-bold uppercase font-mono inline-block ${getActionColor(selectedLog.action)}`}
                    >
                      {selectedLog.action}
                    </span>
                  </div>

                  <div className="bg-gray-50 border border-black p-4">
                    <label className="tim-meta block mb-2">BẢNG</label>
                    <div className="font-mono font-bold uppercase text-sm">
                      {selectedLog.tableName}
                    </div>
                  </div>

                  <div className="bg-gray-50 border border-black p-4">
                    <label className="tim-meta block mb-2">RECORD ID</label>
                    <div className="font-mono text-sm">
                      {selectedLog.recordId}
                    </div>
                  </div>

                  <div className="bg-gray-50 border border-black p-4">
                    <label className="tim-meta block mb-2">THỜI GIAN</label>
                    <div className="font-mono text-sm">
                      {formatDateTime(selectedLog.createdAt)}
                    </div>
                  </div>
                </div>

                {/* User Info */}
                <div className="bg-white border-l-4 border-l-[#F3E600] border border-black p-4">
                  <label className="tim-meta block mb-2">NGƯỜI THỰC HIỆN</label>
                  <div className="flex items-center gap-4">
                    <div className="bg-black text-white px-3 py-2 rounded-none">
                      <span className="font-mono text-xs uppercase">
                        {(
                          selectedLog.user?.profile?.fullName || "N/A"
                        ).substring(0, 2)}
                      </span>
                    </div>
                    <div>
                      <div className="font-bold uppercase text-sm">
                        {selectedLog.user?.profile?.fullName || "N/A"}
                      </div>
                      <div className="font-mono text-xs text-gray-500">
                        {selectedLog.user?.email || "N/A"}
                      </div>
                    </div>
                  </div>
                </div>

                {/* Description */}
                {selectedLog.description && (
                  <div className="bg-gray-50 border border-black p-4">
                    <label className="tim-meta block mb-2">MÔ TẢ</label>
                    <div className="text-sm">{selectedLog.description}</div>
                  </div>
                )}

                {/* Data Comparison */}
                <div className="grid grid-cols-2 gap-4">
                  {selectedLog.oldData && (
                    <div className="bg-white border border-black">
                      <div className="bg-black text-white p-3 border-b border-black">
                        <span className="tim-meta text-white">DỮ LIỆU CŨ</span>
                      </div>
                      <div className="p-4 max-h-64 overflow-y-auto">
                        <pre className="text-xs font-mono whitespace-pre-wrap">
                          {JSON.stringify(selectedLog.oldData, null, 2)}
                        </pre>
                      </div>
                    </div>
                  )}

                  {selectedLog.newData && (
                    <div className="bg-white border border-black">
                      <div className="bg-black text-white p-3 border-b border-black">
                        <span className="tim-meta text-white">DỮ LIỆU MỚI</span>
                      </div>
                      <div className="p-4 max-h-64 overflow-y-auto">
                        <pre className="text-xs font-mono whitespace-pre-wrap">
                          {JSON.stringify(selectedLog.newData, null, 2)}
                        </pre>
                      </div>
                    </div>
                  )}
                </div>

                {/* Close Button */}
                <div className="flex justify-end pt-4 border-t border-black">
                  <Button
                    onClick={() => setShowDetailModal(false)}
                    className="rounded-none border border-black bg-white text-black hover:bg-black hover:text-white h-10 px-8 font-bold uppercase"
                  >
                    ĐÓNG
                  </Button>
                </div>
              </div>
            )}
          </DialogContent>
        </Dialog>
      </div>
    </div>
  );
};

export default AuditLogsPage;

import { useState, useEffect, useCallback } from "react";
import {
  Mail,
  RefreshCw,
  Send,
  CheckCircle,
  XCircle,
  Clock,
  ShieldCheck,
} from "lucide-react";
import toast from "react-hot-toast";
import {
  Card,
  CardHeader,
  CardTitle,
  CardContent,
  Button,
} from "@/components/ui";
import { emailVerificationService } from "@/apis";
import { formatDate } from "@/utils/dateUtils";

const EmailVerificationPage = () => {
  const [verifications, setVerifications] = useState([]);
  const [loading, setLoading] = useState(false);
  const [stats, setStats] = useState({
    total: 0,
    pending: 0,
    verified: 0,
    expired: 0,
  });

  // Filters
  const [statusFilter, setStatusFilter] = useState("all");
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const itemsPerPage = 10;

  // Fetch verifications
  const fetchVerifications = useCallback(async () => {
    try {
      setLoading(true);
      const params = {
        page: currentPage,
        limit: itemsPerPage,
        status: statusFilter === "all" ? undefined : statusFilter,
      };
      const response = await emailVerificationService.getAll(params);
      if (response.success) {
        setVerifications(response.data || []);
        setTotalPages(response.pagination?.totalPages || 1);
      }
    } catch (error) {
      toast.error("Lỗi khi tải danh sách xác thực email");
      console.error(error);
    } finally {
      setLoading(false);
    }
  }, [currentPage, itemsPerPage, statusFilter]);

  // Fetch stats
  const fetchStats = useCallback(async () => {
    try {
      const statsData = await emailVerificationService.getStats();
      setStats(statsData);
    } catch (error) {
      console.error("Failed to fetch stats:", error);
    }
  }, []);

  useEffect(() => {
    fetchVerifications();
    fetchStats();
  }, [fetchVerifications, fetchStats]);

  // Handle resend email
  const handleResend = async (userId, email) => {
    if (!window.confirm(`Gửi lại email xác thực đến ${email}?`)) return;

    try {
      const response = await emailVerificationService.resend(userId);
      if (response.success) {
        toast.success("Đã gửi lại email xác thực");
        fetchVerifications();
        fetchStats();
      }
    } catch (error) {
      toast.error("Lỗi khi gửi lại email");
      console.error(error);
    }
  };

  // Handle manual verify (Admin)
  const handleManualVerify = async (userId, email) => {
    if (
      !window.confirm(
        `Xác thực thủ công email ${email}?\n\nLưu ý: Chỉ sử dụng khi user không nhận được email hoặc token đã hết hạn.`,
      )
    )
      return;

    try {
      const response = await emailVerificationService.manualVerify(userId);
      if (response.success) {
        toast.success("Đã xác thực email thành công");
        fetchVerifications();
        fetchStats();
      }
    } catch (error) {
      toast.error(error.response?.data?.message || "Lỗi khi xác thực email");
      console.error(error);
    }
  };

  // Get status info
  const getStatusInfo = (verification) => {
    const now = new Date();
    const expiresAt = new Date(verification.expiresAt);

    if (verification.verifiedAt) {
      return {
        label: "Đã xác thực",
        color: "text-green-600 bg-green-100",
        icon: <CheckCircle className="w-4 h-4" />,
      };
    }
    if (expiresAt < now) {
      return {
        label: "Hết hạn",
        color: "text-red-600 bg-red-100",
        icon: <XCircle className="w-4 h-4" />,
      };
    }
    return {
      label: "Chờ xác thực",
      color: "text-yellow-600 bg-yellow-100",
      icon: <Clock className="w-4 h-4" />,
    };
  };

  return (
    <div className="min-h-screen p-8 bg-background relative">
      {/* Enhanced grid background with dots */}
      <div className="absolute inset-0 bg-grid-dots opacity-60 pointer-events-none"></div>
      <div className="absolute inset-0 bg-grid-lines opacity-20 pointer-events-none"></div>

      <div className="relative z-10 space-y-6 max-w-[1600px] mx-auto">
        {/* Header */}
        <div className="flex items-end justify-between border-b-2 border-black pb-6">
          <div className="flex items-center gap-6">
            <div className="accent-bar h-16"></div>
            <div>
              <h1 className="tim-title">XÁC THỰC EMAIL</h1>
              <div className="flex items-center gap-4 mt-2">
                <span className="tim-system bg-black text-white px-2 py-1">
                  SYSTEM // EMAIL VERIFICATION
                </span>
                <p className="tim-meta">QUẢN LÝ XÁC THỰC EMAIL</p>
              </div>
            </div>
          </div>
          <Button
            onClick={() => fetchVerifications()}
            disabled={loading}
            variant="outline"
            className="h-12 w-12 rounded-none border border-black hover:bg-black hover:text-white"
          >
            <RefreshCw className={`h-4 w-4 ${loading ? "animate-spin" : ""}`} />
          </Button>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="bg-white border border-black p-6 shadow-sm hover:shadow-hard transition-all">
            <div className="flex items-center justify-between mb-2">
              <span className="tim-meta">TỔNG SỐ</span>
              <Mail className="h-5 w-5 text-gray-400" />
            </div>
            <div className="text-4xl font-black tracking-tighter">
              {stats.total}
            </div>
          </div>
          <div className="bg-white border border-black p-6 shadow-sm hover:shadow-hard transition-all border-l-4 border-l-[#F3E600]">
            <div className="flex items-center justify-between mb-2">
              <span className="tim-meta">CHỜ XÁC THỰC</span>
              <Clock className="h-5 w-5 text-[#F3E600]" />
            </div>
            <div className="text-4xl font-black tracking-tighter text-[#F3E600]">
              {stats.pending}
            </div>
          </div>
          <div className="bg-white border border-black p-6 shadow-sm hover:shadow-hard transition-all">
            <div className="flex items-center justify-between mb-2">
              <span className="tim-meta">ĐÃ XÁC THỰC</span>
              <CheckCircle className="h-5 w-5 text-green-600" />
            </div>
            <div className="text-4xl font-black tracking-tighter text-green-600">
              {stats.verified}
            </div>
          </div>
          <div className="bg-white border border-black p-6 shadow-sm hover:shadow-hard transition-all">
            <div className="flex items-center justify-between mb-2">
              <span className="tim-meta">HẾT HẠN</span>
              <XCircle className="h-5 w-5 text-red-600" />
            </div>
            <div className="text-4xl font-black tracking-tighter text-red-600">
              {stats.expired}
            </div>
          </div>
        </div>

        {/* Filter Bar */}
        <div className="bg-white border border-black p-4 shadow-sm">
          <div className="flex items-center justify-between">
            <span className="tim-meta">BỘ LỌC DỮ LIỆU</span>
            <select
              value={statusFilter}
              onChange={(e) => {
                setStatusFilter(e.target.value);
                setCurrentPage(1);
              }}
              className="h-10 px-4 border border-black rounded-none bg-white tim-body uppercase focus:outline-none focus:bg-yellow-50"
            >
              <option value="all">TẤT CẢ TRẠNG THÁI</option>
              <option value="pending">CHỜ XÁC THỰC</option>
              <option value="verified">ĐÃ XÁC THỰC</option>
              <option value="expired">HẾT HẠN</option>
            </select>
          </div>
        </div>
        {/* Data Table */}
        <div className="bg-white border border-black shadow-sm overflow-hidden">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20 bg-gray-50">
              <div className="w-8 h-8 border-2 border-black border-t-transparent rounded-full animate-spin mb-2"></div>
              <span className="font-mono text-xs uppercase text-gray-500">
                LOADING DATA...
              </span>
            </div>
          ) : verifications.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20">
              <Mail className="h-12 w-12 text-gray-300 mb-4" />
              <div className="font-bold uppercase text-gray-400">
                KHÔNG TÌM THẤY DỮ LIỆU
              </div>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-black text-white tim-table-header">
                    <th className="p-4 border-r border-black/20 w-[60px]">
                      ID
                    </th>
                    <th className="p-4 border-r border-black/20">EMAIL</th>
                    <th className="p-4 border-r border-black/20">USER</th>
                    <th className="p-4 border-r border-black/20">TRẠNG THÁI</th>
                    <th className="p-4 border-r border-black/20">NGÀY TẠO</th>
                    <th className="p-4 border-r border-black/20">HẾT HẠN</th>
                    <th className="p-4 border-r border-black/20">
                      NGÀY XÁC THỰC
                    </th>
                    <th className="p-4 text-center">THAO TÁC</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-black/5">
                  {verifications.map((verification) => {
                    const statusInfo = getStatusInfo(verification);
                    return (
                      <tr
                        key={verification.id}
                        className="hover:bg-yellow-50 group transition-colors"
                      >
                        <td className="p-4 font-mono text-sm text-gray-400 border-r border-black/5">
                          #{verification.id}
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <div className="font-mono text-sm font-medium">
                            {verification.email}
                          </div>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <div className="font-mono text-sm text-gray-600">
                            {verification.user?.email || "—"}
                          </div>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <span
                            className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-none border border-black text-[10px] font-bold uppercase font-mono ${statusInfo.color}`}
                          >
                            {statusInfo.icon}
                            {statusInfo.label}
                          </span>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <div className="font-mono text-sm text-gray-500">
                            {formatDate(verification.createdAt)}
                          </div>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <div className="font-mono text-sm text-gray-500">
                            {formatDate(verification.expiresAt)}
                          </div>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <div className="font-mono text-sm text-gray-500">
                            {verification.verifiedAt
                              ? formatDate(verification.verifiedAt)
                              : "—"}
                          </div>
                        </td>
                        <td className="p-4 text-center">
                          {!verification.verifiedAt ? (
                            <div className="flex gap-2 justify-center">
                              <Button
                                size="sm"
                                variant="outline"
                                onClick={() =>
                                  handleResend(
                                    verification.userId,
                                    verification.email,
                                  )
                                }
                                className="rounded-none border border-black hover:bg-black hover:text-white uppercase text-[10px] font-bold h-8"
                              >
                                <Send className="w-3 h-3 mr-1" />
                                GỬI
                              </Button>
                              <Button
                                size="sm"
                                onClick={() =>
                                  handleManualVerify(
                                    verification.userId,
                                    verification.email,
                                  )
                                }
                                className="rounded-none bg-[#F3E600] hover:bg-black text-black hover:text-white border border-black uppercase text-[10px] font-bold h-8"
                              >
                                <ShieldCheck className="w-3 h-3 mr-1" />
                                XÁC THỰC
                              </Button>
                            </div>
                          ) : (
                            <span className="text-green-600 text-xs uppercase font-mono font-bold">
                              ✓ ĐÃ XÁC THỰC
                            </span>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}

          {/* Pagination */}
          {totalPages > 1 && (
            <div className="flex items-center justify-between p-4 border-t border-black bg-gray-50 font-mono text-xs uppercase">
              <div>HIỂN THỊ {verifications.length} KẾT QUẢ</div>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                  disabled={currentPage === 1}
                  className="rounded-none border-black h-8 hover:bg-black hover:text-white"
                >
                  TRƯỚC
                </Button>
                <span className="flex items-center px-4 font-bold">
                  {currentPage}
                </span>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() =>
                    setCurrentPage((p) => Math.min(totalPages, p + 1))
                  }
                  disabled={currentPage === totalPages}
                  className="rounded-none border-black h-8 hover:bg-black hover:text-white"
                >
                  SAU
                </Button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default EmailVerificationPage;

import { useState, useEffect, useCallback } from "react";
import {
  Monitor,
  RefreshCw,
  Eye,
  Ban,
  CheckCircle,
  XCircle,
  Clock,
  Smartphone,
  AlertCircle,
} from "lucide-react";
import toast from "react-hot-toast";
import {
  Card,
  CardHeader,
  CardTitle,
  CardContent,
  Button,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui";
import { loginHistoryService } from "@/apis";
import { formatDate } from "@/utils/dateUtils";
import { useAuthStore } from "@/stores/authStore";
import TimStatsCard from "@/components/admin/TimStatsCard";

const LoginHistoryPage = () => {
  const { user: currentUser } = useAuthStore();
  const [sessions, setSessions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedSession, setSelectedSession] = useState(null);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [stats, setStats] = useState({
    total: 0,
    active: 0,
    revoked: 0,
    expired: 0,
  });

  // Filters
  const [statusFilter, setStatusFilter] = useState("all");
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const itemsPerPage = 10;

  // Fetch sessions
  const fetchSessions = useCallback(async () => {
    try {
      setLoading(true);
      const params = {
        page: currentPage,
        limit: itemsPerPage,
        isActive:
          statusFilter === "all" ? undefined : statusFilter === "active",
      };
      const response = await loginHistoryService.getAll(params);
      if (response.success) {
        setSessions(response.data || []);
        setTotalPages(response.pagination?.totalPages || 1);
      }
    } catch (error) {
      toast.error("Lỗi khi tải lịch sử đăng nhập");
      console.error(error);
    } finally {
      setLoading(false);
    }
  }, [currentPage, itemsPerPage, statusFilter]);

  // Fetch stats
  const fetchStats = useCallback(async () => {
    try {
      const statsData = await loginHistoryService.getStats();
      setStats(statsData);
    } catch (error) {
      console.error("Failed to fetch stats:", error);
    }
  }, []);

  useEffect(() => {
    fetchSessions();
    fetchStats();
  }, [fetchSessions, fetchStats]);

  // View detail
  const handleViewDetail = async (session) => {
    try {
      const response = await loginHistoryService.getById(session.id);
      if (response.success) {
        setSelectedSession(response.data);
        setShowDetailModal(true);
      }
    } catch (error) {
      toast.error("Lỗi khi tải chi tiết session");
      console.error(error);
    }
  };

  // Revoke session
  const handleRevoke = async (sessionId) => {
    if (!window.confirm("Bạn có chắc muốn vô hiệu hóa session này?")) return;

    try {
      const response = await loginHistoryService.revoke(sessionId);
      if (response.success) {
        toast.success("Đã vô hiệu hóa session");
        fetchSessions();
        fetchStats();
      }
    } catch (error) {
      toast.error("Lỗi khi vô hiệu hóa session");
      console.error(error);
    }
  };

  // Revoke all except current
  const handleRevokeAll = async (userId) => {
    if (
      !window.confirm(
        "Bạn có chắc muốn đăng xuất tất cả thiết bị khác? (Giữ lại session hiện tại)",
      )
    )
      return;

    try {
      // Lấy currentSessionId từ localStorage (nếu có lưu)
      const currentSessionId = loginHistoryService.getCurrentSessionId();
      const response = await loginHistoryService.revokeAll(
        userId,
        currentSessionId,
      );
      if (response.success) {
        toast.success(response.message || "Đã đăng xuất tất cả thiết bị khác");
        fetchSessions();
        fetchStats();
      }
    } catch (error) {
      toast.error(
        error.response?.data?.message || "Lỗi khi đăng xuất tất cả thiết bị",
      );
      console.error(error);
    }
  };

  // Get status info (sử dụng status computed từ backend)
  const getStatusInfo = (session) => {
    // Backend đã compute status: active, revoked, expired
    const status = session.status || "active";

    if (status === "revoked" || !session.isActive) {
      return {
        label: "Đã vô hiệu",
        color: "text-gray-600 bg-gray-100",
        icon: <Ban className="w-4 h-4" />,
      };
    }
    if (status === "expired") {
      return {
        label: "Hết hạn",
        color: "text-red-600 bg-red-100",
        icon: <XCircle className="w-4 h-4" />,
      };
    }
    return {
      label: "Đang hoạt động",
      color: "text-green-600 bg-green-100",
      icon: <CheckCircle className="w-4 h-4" />,
    };
  };

  // Get device icon
  const getDeviceIcon = (deviceName) => {
    if (!deviceName) return <Monitor className="w-4 h-4" />;
    const lower = deviceName.toLowerCase();
    if (
      lower.includes("mobile") ||
      lower.includes("android") ||
      lower.includes("iphone")
    ) {
      return <Smartphone className="w-4 h-4" />;
    }
    return <Monitor className="w-4 h-4" />;
  };

  // Truncate device name
  const truncateDevice = (name) => {
    if (!name) return "Unknown";
    return name.length > 50 ? `${name.substring(0, 50)  }...` : name;
  };

  return (
    <div className="min-h-screen p-8 bg-background relative">
      {/* Enhanced grid background with dots */}
      <div className="absolute inset-0 bg-grid-dots opacity-60 pointer-events-none"></div>
      <div className="absolute inset-0 bg-grid-lines opacity-20 pointer-events-none"></div>

      <div className="relative z-10 space-y-6 max-w-[1600px] mx-auto">
        {/* Header */}
        <div className="flex items-end justify-between border-b-2 border-black pb-6">
          <div className="flex items-center gap-6">
            <div className="accent-bar h-16"></div>
            <div>
              <h1 className="tim-title">LỊCH SỚ ĐĂNG NHẬP</h1>
              <div className="flex items-center gap-4 mt-2">
                <span className="tim-system bg-black text-white px-2 py-1">
                  SYSTEM // LOGIN HISTORY
                </span>
                <p className="tim-meta">QUẢN LÝ SESSIONS VÀ THIẾT BỊ</p>
              </div>
            </div>
          </div>
          <Button
            onClick={() => fetchSessions()}
            disabled={loading}
            variant="outline"
            className="h-12 w-12 rounded-none border border-black hover:bg-black hover:text-white"
          >
            <RefreshCw className={`h-4 w-4 ${loading ? "animate-spin" : ""}`} />
          </Button>
        </div>

        {/* Thống kê nhanh */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <TimStatsCard
            title="TỔNG SESSION"
            value={stats.total}
            icon={Monitor}
            serial="LGN-001"
          />
          <TimStatsCard
            title="ĐANG HOẠT ĐỘNG"
            value={stats.active}
            icon={CheckCircle}
            serial="LGN-002"
            textColor="text-emerald-600"
          />
          <TimStatsCard
            title="ĐÃ VÔ HIỆU"
            value={stats.revoked}
            icon={Ban}
            serial="LGN-003"
            textColor="text-gray-500"
          />
          <TimStatsCard
            title="HẾT HẠN"
            value={stats.expired}
            icon={XCircle}
            serial="LGN-004"
            color="bg-yellow-50"
            textColor="text-red-600"
          />
        </div>

        {/* Filter Bar */}
        <div className="bg-white border border-black p-4 shadow-sm">
          <div className="flex items-center justify-between flex-wrap gap-4">
            <span className="tim-meta">BỘ LỌC DỮ LIỆU</span>
            <div className="flex gap-2">
              <select
                value={statusFilter}
                onChange={(e) => {
                  setStatusFilter(e.target.value);
                  setCurrentPage(1);
                }}
                className="h-10 px-4 border border-black rounded-none bg-white tim-body uppercase focus:outline-none focus:bg-yellow-50"
              >
                <option value="all">TẤT CẢ TRẠNG THÁI</option>
                <option value="active">ĐANG HOẠT ĐỘNG</option>
                <option value="inactive">ĐÃ VÔ HIỆU</option>
              </select>
              {currentUser && (
                <Button
                  variant="outline"
                  onClick={() => handleRevokeAll(currentUser.id)}
                  className="h-10 rounded-none border border-black hover:bg-black hover:text-white uppercase text-xs font-bold"
                >
                  <Ban className="w-4 h-4 mr-2" />
                  ĐĂNG XUẤT TẤT CẢ
                </Button>
              )}
            </div>
          </div>
        </div>

        {/* Data Table */}
        <div className="bg-white border border-black shadow-sm overflow-hidden">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20 bg-gray-50">
              <div className="w-8 h-8 border-2 border-black border-t-transparent rounded-full animate-spin mb-2"></div>
              <span className="font-mono text-xs uppercase text-gray-500">
                LOADING DATA...
              </span>
            </div>
          ) : sessions.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20">
              <Monitor className="h-12 w-12 text-gray-300 mb-4" />
              <div className="font-bold uppercase text-gray-400">
                KHÔNG TÌM THẤY DỮ LIỆU
              </div>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-black text-white tim-table-header">
                    <th className="p-4 border-r border-black/20 w-[60px]">
                      ID
                    </th>
                    <th className="p-4 border-r border-black/20">USER</th>
                    <th className="p-4 border-r border-black/20">THIẾT BỊ</th>
                    <th className="p-4 border-r border-black/20">IP ADDRESS</th>
                    <th className="p-4 border-r border-black/20">TRẠNG THÁI</th>
                    <th className="p-4 border-r border-black/20">ĐĂNG NHẬP</th>
                    <th className="p-4 border-r border-black/20">
                      DÙNG GẦN NHẤT
                    </th>
                    <th className="p-4 border-r border-black/20">HẾT HẠN</th>
                    <th className="p-4 text-center">THAO TÁC</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-black/5">
                  {sessions.map((session) => {
                    const statusInfo = getStatusInfo(session);
                    return (
                      <tr
                        key={session.id}
                        className="hover:bg-yellow-50 group transition-colors"
                      >
                        <td className="p-4 font-mono text-sm text-gray-400 border-r border-black/5">
                          #{session.id}
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <div>
                            <div className="font-bold uppercase text-sm">
                              {session.user?.profile?.fullName || "N/A"}
                            </div>
                            <div className="text-gray-500 text-xs font-mono">
                              {session.user?.email || "N/A"}
                            </div>
                          </div>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <div className="flex items-center gap-2">
                            {getDeviceIcon(session.deviceName)}
                            <span className="truncate max-w-[200px] text-sm">
                              {truncateDevice(session.deviceName)}
                            </span>
                          </div>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <span className="font-mono text-sm">
                            {session.ipAddress}
                          </span>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <span
                            className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-none border border-black text-[10px] font-bold uppercase font-mono ${statusInfo.color}`}
                          >
                            {statusInfo.icon}
                            {statusInfo.label}
                          </span>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <span className="font-mono text-sm text-gray-500">
                            {formatDate(session.createdAt)}
                          </span>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <span className="font-mono text-sm text-gray-500">
                            {formatDate(session.lastUsedAt)}
                          </span>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <span className="font-mono text-sm text-gray-500">
                            {formatDate(session.expiresAt)}
                          </span>
                        </td>
                        <td className="p-4 text-center">
                          <div className="flex items-center justify-center gap-2">
                            <Button
                              size="sm"
                              variant="ghost"
                              onClick={() => handleViewDetail(session)}
                              className="rounded-none border border-transparent hover:border-black hover:bg-white h-8"
                            >
                              <Eye className="w-4 h-4" />
                            </Button>
                            {session.isActive && (
                              <Button
                                size="sm"
                                variant="ghost"
                                onClick={() => handleRevoke(session.id)}
                                className="rounded-none border border-transparent hover:border-red-600 hover:bg-red-50 text-red-600 hover:text-red-700 h-8"
                              >
                                <Ban className="w-4 h-4" />
                              </Button>
                            )}
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}

          {/* Pagination */}
          {totalPages > 1 && (
            <div className="flex items-center justify-between p-4 border-t border-black bg-gray-50 font-mono text-xs uppercase">
              <div>HIỂN THỊ {sessions.length} KẾT QUẢ</div>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                  disabled={currentPage === 1}
                  className="rounded-none border-black h-8 hover:bg-black hover:text-white"
                >
                  TRƯỚC
                </Button>
                <span className="flex items-center px-4 font-bold">
                  {currentPage}
                </span>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() =>
                    setCurrentPage((p) => Math.min(totalPages, p + 1))
                  }
                  disabled={currentPage === totalPages}
                  className="rounded-none border-black h-8 hover:bg-black hover:text-white"
                >
                  SAU
                </Button>
              </div>
            </div>
          )}
        </div>

        {/* Detail Modal */}
        <Dialog open={showDetailModal} onOpenChange={setShowDetailModal}>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>Chi tiết Session #{selectedSession?.id}</DialogTitle>
            </DialogHeader>
            {selectedSession && (
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-sm font-medium text-gray-500">
                      User
                    </label>
                    <p className="mt-1">
                      {selectedSession.user?.profile?.fullName || "N/A"}
                      <br />
                      <span className="text-sm text-gray-500">
                        {selectedSession.user?.email}
                      </span>
                    </p>
                  </div>
                  <div>
                    <label className="text-sm font-medium text-gray-500">
                      Trạng thái
                    </label>
                    <p className="mt-1">
                      {(() => {
                        const statusInfo = getStatusInfo(selectedSession);
                        return (
                          <span
                            className={`inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium ${statusInfo.color}`}
                          >
                            {statusInfo.icon}
                            {statusInfo.label}
                          </span>
                        );
                      })()}
                    </p>
                  </div>
                  <div className="col-span-2">
                    <label className="text-sm font-medium text-gray-500">
                      Thiết bị
                    </label>
                    <div className="mt-1 flex items-center gap-2">
                      {getDeviceIcon(selectedSession.deviceName)}
                      <p className="break-all">{selectedSession.deviceName}</p>
                    </div>
                  </div>
                  <div>
                    <label className="text-sm font-medium text-gray-500">
                      IP Address
                    </label>
                    <p className="mt-1 font-mono">
                      {selectedSession.ipAddress}
                    </p>
                  </div>
                  <div>
                    <label className="text-sm font-medium text-gray-500">
                      Device ID
                    </label>
                    <p className="mt-1 font-mono">
                      {selectedSession.deviceId || "N/A"}
                    </p>
                  </div>
                  <div>
                    <label className="text-sm font-medium text-gray-500">
                      Đăng nhập lúc
                    </label>
                    <p className="mt-1">
                      {formatDate(selectedSession.createdAt)}
                    </p>
                  </div>
                  <div>
                    <label className="text-sm font-medium text-gray-500">
                      Sử dụng lần cuối
                    </label>
                    <p className="mt-1">
                      {formatDate(selectedSession.lastUsedAt)}
                    </p>
                  </div>
                  <div>
                    <label className="text-sm font-medium text-gray-500">
                      Hết hạn lúc
                    </label>
                    <p className="mt-1">
                      {formatDate(selectedSession.expiresAt)}
                    </p>
                  </div>
                  <div>
                    <label className="text-sm font-medium text-gray-500">
                      Refresh Token
                    </label>
                    <p className="mt-1 font-mono text-xs truncate">
                      {selectedSession.refreshToken}
                    </p>
                  </div>
                </div>

                {selectedSession.isActive && (
                  <div className="pt-4 border-t">
                    <Button
                      variant="destructive"
                      onClick={() => {
                        handleRevoke(selectedSession.id);
                        setShowDetailModal(false);
                      }}
                      className="w-full"
                    >
                      <Ban className="w-4 h-4 mr-2" />
                      Vô hiệu hóa Session
                    </Button>
                  </div>
                )}
              </div>
            )}
          </DialogContent>
        </Dialog>
      </div>
    </div>
  );
};

export default LoginHistoryPage;

import { useState, useEffect, useCallback } from "react";
import {
  Key,
  RefreshCw,
  CheckCircle,
  XCircle,
  Clock,
  MapPin,
} from "lucide-react";
import toast from "react-hot-toast";
import {
  Card,
  CardHeader,
  CardTitle,
  CardContent,
  Button,
} from "@/components/ui";
import { passwordResetService } from "@/apis";
import { formatDate } from "@/utils/dateUtils";

const PasswordResetPage = () => {
  const [resets, setResets] = useState([]);
  const [loading, setLoading] = useState(false);
  const [stats, setStats] = useState({
    total: 0,
    pending: 0,
    used: 0,
    expired: 0,
  });

  // Filters
  const [statusFilter, setStatusFilter] = useState("all");
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const itemsPerPage = 10;

  // Fetch resets
  const fetchResets = useCallback(async () => {
    try {
      setLoading(true);
      const params = {
        page: currentPage,
        limit: itemsPerPage,
        status: statusFilter === "all" ? undefined : statusFilter,
      };
      const response = await passwordResetService.getAll(params);
      if (response.success) {
        setResets(response.data || []);
        setTotalPages(response.pagination?.totalPages || 1);
      }
    } catch (error) {
      toast.error("Lỗi khi tải danh sách reset mật khẩu");
      console.error(error);
    } finally {
      setLoading(false);
    }
  }, [currentPage, itemsPerPage, statusFilter]);

  // Fetch stats
  const fetchStats = useCallback(async () => {
    try {
      const statsData = await passwordResetService.getStats();
      setStats(statsData);
    } catch (error) {
      console.error("Failed to fetch stats:", error);
    }
  }, []);

  useEffect(() => {
    fetchResets();
    fetchStats();
  }, [fetchResets, fetchStats]);

  // Get status info
  const getStatusInfo = (reset) => {
    const now = new Date();
    const expiresAt = new Date(reset.expiresAt);

    if (reset.usedAt) {
      return {
        label: "Đã sử dụng",
        color: "text-green-600 bg-green-100",
        icon: <CheckCircle className="w-4 h-4" />,
      };
    }
    if (expiresAt < now) {
      return {
        label: "Hết hạn",
        color: "text-red-600 bg-red-100",
        icon: <XCircle className="w-4 h-4" />,
      };
    }
    return {
      label: "Chờ sử dụng",
      color: "text-yellow-600 bg-yellow-100",
      icon: <Clock className="w-4 h-4" />,
    };
  };

  // Calculate time remaining
  const getTimeRemaining = (expiresAt) => {
    const now = new Date();
    const expires = new Date(expiresAt);
    const diff = expires - now;

    if (diff <= 0) return "Đã hết hạn";

    const minutes = Math.floor(diff / 60000);
    if (minutes < 60) return `${minutes} phút`;

    const hours = Math.floor(minutes / 60);
    return `${hours} giờ ${minutes % 60} phút`;
  };

  return (
    <div className="min-h-screen p-8 bg-background relative">
      {/* Enhanced grid background with dots */}
      <div className="absolute inset-0 bg-grid-dots opacity-60 pointer-events-none"></div>
      <div className="absolute inset-0 bg-grid-lines opacity-20 pointer-events-none"></div>

      <div className="relative z-10 space-y-6 max-w-[1600px] mx-auto">
        {/* Header */}
        <div className="flex items-end justify-between border-b-2 border-black pb-6">
          <div className="flex items-center gap-6">
            <div className="accent-bar h-16"></div>
            <div>
              <h1 className="tim-title">RESET MẬT KHẨU</h1>
              <div className="flex items-center gap-4 mt-2">
                <span className="tim-system bg-black text-white px-2 py-1">
                  SYSTEM // PASSWORD RESET
                </span>
                <p className="tim-meta">QUẢN LÝ YÊU CẦU ĐẶT LẠI MẬT KHẨU</p>
              </div>
            </div>
          </div>
          <Button
            onClick={() => fetchResets()}
            disabled={loading}
            variant="outline"
            className="h-12 w-12 rounded-none border border-black hover:bg-black hover:text-white"
          >
            <RefreshCw className={`h-4 w-4 ${loading ? "animate-spin" : ""}`} />
          </Button>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="bg-white border border-black p-6 shadow-sm hover:shadow-hard transition-all">
            <div className="flex items-center justify-between mb-2">
              <span className="tim-meta">TỔNG SỐ</span>
              <Key className="h-5 w-5 text-gray-400" />
            </div>
            <div className="text-4xl font-black tracking-tighter">
              {stats.total}
            </div>
          </div>
          <div className="bg-white border border-black p-6 shadow-sm hover:shadow-hard transition-all border-l-4 border-l-[#F3E600]">
            <div className="flex items-center justify-between mb-2">
              <span className="tim-meta">CHỜ SỆ DỤNG</span>
              <Clock className="h-5 w-5 text-[#F3E600]" />
            </div>
            <div className="text-4xl font-black tracking-tighter text-[#F3E600]">
              {stats.pending}
            </div>
          </div>
          <div className="bg-white border border-black p-6 shadow-sm hover:shadow-hard transition-all">
            <div className="flex items-center justify-between mb-2">
              <span className="tim-meta">ĐÃ SỆ DỤNG</span>
              <CheckCircle className="h-5 w-5 text-green-600" />
            </div>
            <div className="text-4xl font-black tracking-tighter text-green-600">
              {stats.used}
            </div>
          </div>
          <div className="bg-white border border-black p-6 shadow-sm hover:shadow-hard transition-all">
            <div className="flex items-center justify-between mb-2">
              <span className="tim-meta">HẾT HẠN</span>
              <XCircle className="h-5 w-5 text-red-600" />
            </div>
            <div className="text-4xl font-black tracking-tighter text-red-600">
              {stats.expired}
            </div>
          </div>
        </div>

        {/* Filter Bar */}
        <div className="bg-white border border-black p-4 shadow-sm">
          <div className="flex items-center justify-between">
            <span className="tim-meta">BỘ LỌC DỮ LIỆU</span>
            <select
              value={statusFilter}
              onChange={(e) => {
                setStatusFilter(e.target.value);
                setCurrentPage(1);
              }}
              className="h-10 px-4 border border-black rounded-none bg-white tim-body uppercase focus:outline-none focus:bg-yellow-50"
            >
              <option value="all">TẤT CẢ TRẠNG THÁI</option>
              <option value="pending">CHỜ SỆ DỤNG</option>
              <option value="used">ĐÃ SỆ DỤNG</option>
              <option value="expired">HẾT HẠN</option>
            </select>
          </div>
        </div>
        {/* Data Table */}
        <div className="bg-white border border-black shadow-sm overflow-hidden">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20 bg-gray-50">
              <div className="w-8 h-8 border-2 border-black border-t-transparent rounded-full animate-spin mb-2"></div>
              <span className="font-mono text-xs uppercase text-gray-500">
                LOADING DATA...
              </span>
            </div>
          ) : resets.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20">
              <Key className="h-12 w-12 text-gray-300 mb-4" />
              <div className="font-bold uppercase text-gray-400">
                KHÔNG TÌM THẤY DỮ LIỆU
              </div>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-black text-white tim-table-header">
                    <th className="p-4 border-r border-black/20 w-[60px]">
                      ID
                    </th>
                    <th className="p-4 border-r border-black/20">EMAIL</th>
                    <th className="p-4 border-r border-black/20">USER</th>
                    <th className="p-4 border-r border-black/20">IP ADDRESS</th>
                    <th className="p-4 border-r border-black/20">TRẠNG THÁI</th>
                    <th className="p-4 border-r border-black/20">NGÀY TẠO</th>
                    <th className="p-4 border-r border-black/20">HẾT HẠN</th>
                    <th className="p-4 border-r border-black/20">CÒN LẠI</th>
                    <th className="p-4">ĐÃ DÙNG</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-black/5">
                  {resets.map((reset) => {
                    const statusInfo = getStatusInfo(reset);
                    return (
                      <tr
                        key={reset.id}
                        className="hover:bg-yellow-50 group transition-colors"
                      >
                        <td className="p-4 font-mono text-sm text-gray-400 border-r border-black/5">
                          #{reset.id}
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <div className="font-mono text-sm font-medium">
                            {reset.email}
                          </div>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <div className="font-mono text-sm text-gray-600">
                            {reset.user?.email || "—"}
                          </div>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <div className="flex items-center gap-1 font-mono text-sm text-gray-600">
                            <MapPin className="w-3 h-3 text-gray-400" />
                            {reset.ipAddress}
                          </div>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <span
                            className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-none border border-black text-[10px] font-bold uppercase font-mono ${statusInfo.color}`}
                          >
                            {statusInfo.icon}
                            {statusInfo.label}
                          </span>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <div className="font-mono text-sm text-gray-500">
                            {formatDate(reset.createdAt)}
                          </div>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          <div className="font-mono text-sm text-gray-500">
                            {formatDate(reset.expiresAt)}
                          </div>
                        </td>
                        <td className="p-4 border-r border-black/5">
                          {!reset.usedAt && (
                            <span
                              className={`font-mono text-sm font-bold ${new Date(reset.expiresAt) > new Date() ? "text-[#F3E600]" : "text-red-600"}`}
                            >
                              {getTimeRemaining(reset.expiresAt)}
                            </span>
                          )}
                        </td>
                        <td className="p-4">
                          <div className="font-mono text-sm text-gray-500">
                            {reset.usedAt ? formatDate(reset.usedAt) : "—"}
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}

          {/* Pagination */}
          {totalPages > 1 && (
            <div className="flex items-center justify-between p-4 border-t border-black bg-gray-50 font-mono text-xs uppercase">
              <div>HIỂN THỊ {resets.length} KẾT QUẢ</div>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                  disabled={currentPage === 1}
                  className="rounded-none border-black h-8 hover:bg-black hover:text-white"
                >
                  TRƯỚC
                </Button>
                <span className="flex items-center px-4 font-bold">
                  {currentPage}
                </span>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() =>
                    setCurrentPage((p) => Math.min(totalPages, p + 1))
                  }
                  disabled={currentPage === totalPages}
                  className="rounded-none border-black h-8 hover:bg-black hover:text-white"
                >
                  SAU
                </Button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

