            )}
          </SectionCard>
        </div>

        {/* Right: Action panel + QR + Voucher */}
        <div className="space-y-4 lg:sticky lg:top-6 lg:self-start">
          <SectionCard title="Thanh toán thủ công" titleIcon={Wallet}>
