                <p className="mt-1 text-sm font-semibold text-foreground uppercase">
                  {paymentStatus === "paid"
                    ? "Đã thanh toán"
                    : paymentStatus.includes("refund")
                      ? "Đã hoàn tiền"
                      : "Chưa thanh toán"}
