              title="Đánh dấu hoàn thành"
              onClick={() => onComplete(bk.id)}
            >
              <CheckCircle className="h-3.5 w-3.5" />
            </Button>
            <Button
              variant="ghost"
              size="sm"
              className="h-8 w-8 p-0 text-muted-foreground hover:bg-muted"
              title="Không đến"
              onClick={() => onNoShow(bk.id)}
            >
              <AlertTriangle className="h-3.5 w-3.5" />
            </Button>
          </>
        )}
      </div>
    </div>
  );
};

