  );

  if (loading) return <ProfileSkeleton />;

  const isSuspended = business?.status === BUSINESS_STATUS.SUSPENDED;
  const canSignContract =
    business?.status === BUSINESS_STATUS.APPROVED && !business?.contractSigned;

