              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="percentage">Phần trăm (%)</SelectItem>
                  <SelectItem value="fixed">Cố định (VND)</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-1.5">
